INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(17001, 1, '🐾 우리 아이 건강 사료 1+1 기획전', '', '✨ 깐깐한 집사들이 선택한 프리미엄 사료!\n💎 기호성 갑! 영양 밸런스까지 완벽하게\n📌 첫 구매 시 무료 샘플팩 증정 🎁\n▶ 지금 혜택받기', '', 1590000.00, 7950),
(17002, 1, '🐕 산책 필수템! LED 하네스 50%', '', '🔥 밤 산책도 안전하고 힙하게!\n🎯 눈에 띄는 광량 + 편안한 착용감\n⚡ 오늘만 이 가격, 선착순 100명!\n▶ 최저가 구매하기', '', 980000.00, 4900),
(17003, 1, '🐱 냥이 취향저격 수제 간식 세트', '', '💎 신선한 원물 그대로 담았습니다\n✨ 무방부제/무색소 건강한 간식\n📞 주문 폭주! 재고 소진 임박\n▶ 냥이 간식 득템하기', '', 370000.00, 1850),
(17004, 1, '🏠 강아지 계단/매트 펫테리어 완성', '', '✨ 관절 건강, 어릴 때부터 챙겨주세요\n📌 인테리어와 조화로운 모던 디자인\n💸 최대 40% 한정 세일 진행 중!\n▶ 구경하러 가기', '', 1660000.00, 8300),
(17005, 1, '✂️ 집에서 끝내는 셀프 미용 키트', '', '🎯 초보자도 5분 만에 깔끔 미용!\n💎 저소음 설계로 아이가 놀라지 않아요\n🚀 로켓 배송으로 내일 바로 사용\n▶ 상세 정보 확인', '', 1050000.00, 5250),
(17006, 1, '🏥 펫 보험 월 1만원대로 든든하게', '', '✨ 병원비 걱정은 이제 그만!\n📌 수술/입원부터 통원치료비까지 보장\n📞 1분 간편 내 아이 보험료 조회\n▶ 무료 상담 신청', '', 440000.00, 2200),
(17007, 1, '🦴 치석 제거 껌 100개입 대용량', '', '🔥 하루 한 개로 끝내는 치아 관리\n🎯 맛있게 씹으면서 입 냄새 제거\n💰 가성비 끝판왕! 오늘만 특가\n▶ 바로 구매하기', '', 1730000.00, 8650),
(17008, 1, '✈️ 반려동물 동반 여행 패키지', '', '🐕 댕댕이랑 같이 비행기 타자!\n✨ 전용 숙소 + 카페 코스 완벽 가이드\n📌 지금 예약 시 전용 캐리어 증정\n▶ 여행 떠나기 ▶', '', 1120000.00, 5600),
(17009, 1, '🧼 저자극 천연 샴푸 향기 뿜뿜', '', '💎 피부가 예민한 아이를 위한 선택\n✨ 은은한 향기가 오래가는 힐링 세정\n🎯 샴푸+브러쉬 세트 구성 특가\n▶ 겟하세요 ✨', '', 510000.00, 2550),
(17010, 1, '🎡 고양이 캣타워 역대급 70% 할인', '', '🔥 튼튼한 원목 소재로 평생 사용!\n📌 우리 냥이만의 프라이빗 아지트\n💰 역대급 할인율 놓치지 마세요\n▶ 지금 클릭 ▶', '', 1800000.00, 9000),
(17011, 1, '📺 펫 전용 CCTV 0원 렌탈 이벤트', '', '✨ 혼자 있는 아이가 걱정된다면?\n📌 실시간 모니터링 + 양방향 대화\n🎯 선착순 상담 완료 시 사은품 증정\n▶ 0원 신청하기', '', 1190000.00, 5950),
(17012, 1, '🧶 스트레스 해소 노즈워크 장난감', '', '💎 킁킁! 분리불안 완화에 직빵\n✨ 다양한 난이도로 지루할 틈 없어요\n🚀 지금 구매 시 간식 한 봉지 증정\n▶ 상품 보러가기', '', 580000.00, 2900),
(17013, 1, '🥤 휴대용 펫 전용 텀블러 할인', '', '🎯 산책 시 물 마시기 편해져요\n📌 원터치 방식 + 물 넘침 방지\n💸 1+1 커플 할인 이벤트 중\n▶ 더 보기', '', 1870000.00, 9350),
(17014, 1, '📸 우리 아이 인생샷 스튜디오', '', '✨ 전문가의 손길로 남기는 견생샷\n💎 소품 무제한 대여 + 수정본 당일 제공\n📌 예약금 환불 가능 이벤트 중\n▶ 촬영 예약하기', '', 1260000.00, 6300),
(17015, 1, '📚 반려동물 건강 관리 바이블', '', '🎯 초보 집사를 위한 필수 가이드북\n✨ 응급처치부터 행동 교정까지 한 권에\n💰 신간 출시 기념 10% 적립\n▶ 도서 구매하기', '', 650000.00, 3250),
(17016, 1, '🦷 고양이 덴탈 칫솔 세트 초특가', '', '🔥 구강 관리가 제일 중요합니다\n📌 부드러운 미세모로 거부감 제로\n⚡ 단 3일간만 진행되는 패키지 특가\n▶ 지금 구매', '', 1940000.00, 9700),
(17017, 1, '🧺 푹신한 마약 방석 꿀잠 보장', '', '✨ 한 번 누우면 못 일어나는 편안함\n💎 구름 솜 충전재로 복원력 최고\n📌 사계절 사용 가능한 리버시블\n▶ 꿀잠템 확인', '', 1330000.00, 6650),
(17018, 1, '🍗 수제 닭가슴살 육포 대용량', '', '🎯 첨가물 제로! 100% 국내산 닭\n✨ 노화 방지 및 면역력 강화 도움\n💰 정기 구독 시 매달 20% 할인\n▶ 구독 신청하기', '', 720000.00, 3600),
(17019, 1, '🧥 겨울 필수! 패딩 조끼 신상', '', '💎 찬바람 완벽 차단! 보온성 갑\n✨ 사이즈 다양, 대형견도 오케이\n📌 무신사 펫 카테고리 1위 등극\n▶ 코디 보러가기', '', 110000.00, 550),
(17020, 1, '🏃‍♂️ 펫 전용 런닝머신 입점', '', '🔥 비 오는 날에도 산책 가능!\n🎯 체중 관리가 필요한 뚱댕이 필수템\n💸 무이자 24개월 할부 혜택\n▶ 제품 자세히 보기', '', 1400000.00, 7000),
(17021, 1, '🧴 펫 전용 미스트 향기 테라피', '', '✨ 푸석한 털을 윤기 있게!\n💎 정전기 방지 + 탈취 효과 한 번에\n📌 휴대하기 좋은 콤팩트 사이즈\n▶ 지금 쇼핑', '', 790000.00, 3950),
(17022, 1, '🥣 세라믹 식기 세트 감성 인테리어', '', '📌 아이들 목 건강을 고려한 높이\n✨ 위생적인 세라믹 재질 + 우드 받침\n💸 오픈 기념 30% 세일 진행\n▶ 감성 식기 보기', '', 180000.00, 900),
(17023, 1, '🎒 우주선 이동장 특가 판매', '', '🎯 밖이 보이는 창으로 불안감 해소\n✨ 가볍고 튼튼한 소재로 집사도 편안\n🚀 오늘 주문 시 내일 도착 보장\n▶ 가격 확인하기', '', 1470000.00, 7350),
(17024, 1, '🥬 동결건조 야채 믹스 영양 간식', '', '💎 편식하는 아이를 위한 필수템\n✨ 사료 위에 톡톡 뿌려주세요\n📌 비타민 가득, 식이섬유 풍부\n▶ 건강 간식 사기', '', 860000.00, 4300),
(17025, 1, '🧬 펫 유전자 검사 키트 출시', '', '🎯 우리 아이 혈통과 유전 질환 확인\n✨ 집에서 간편하게 구강 상피 세포로\n📞 검사 결과 전문가 유선 상담 포함\n▶ 검사 신청하기', '', 250000.00, 1250),
(17026, 1, '🪑 펫 전용 소파 거실의 완성', '', '✨ 주인님 전용 좌석을 마련하세요\n📌 스크래치 방지 패브릭 소재\n💰 한정 수량 특가 진행 중\n▶ 인테리어 보기', '', 1540000.00, 7700),
(17027, 1, '🚑 24시 동물병원 위치 찾기 앱', '', '🎯 내 주변 가장 가까운 응급실은?\n✨ 야간 진료비 비교부터 예약까지\n📌 설치 시 첫 방문 할인권 증정\n▶ 앱 다운로드', '', 930000.00, 4650),
(17028, 1, '🐟 연어 오일 영양제 피모 개선', '', '💎 윤기 나는 털, 모질 개선의 핵심\n✨ 오메가3 풍부, 면역력 강화\n💸 2개 구매 시 1개 추가 증정\n▶ 1+1 구매하기', '', 320000.00, 1600),
(17029, 1, '🧣 커플 머플러 강아지랑 커플룩', '', '✨ 집사랑 댕댕이랑 세트로 맞춰요\n📌 부드러운 니트 소재로 따뜻하게\n💰 인스타그램 인증 시 적립금 5천원\n▶ 세트 보러가기', '', 1610000.00, 8050),
(17030, 1, '🧼 펫 발 전용 클리너 산책 후 필수', '', '🎯 물 없이 닦는 간편 버블 세정\n✨ 자극 없는 성분으로 핥아도 안전\n📌 미세먼지 완벽 세정\n▶ 바로 확인', '', 1000000.00, 5000),
(17031, 1, '⛺ 캠핑 전용 펫 텐트 감성 캠핑', '', '💎 우리 아이만의 캠핑 아지트\n✨ 방수 소재로 야외에서도 안심\n💸 캠핑 시즌 한정 20% 세일\n▶ 캠핑 가기', '', 390000.00, 1950),
(17032, 1, '🍼 분유 & 젖병 세트 영양 보충', '', '🎯 어린 아이부터 노령견까지\n✨ 모유 성분 함유로 기력 회복\n📌 소화가 잘 되는 락토프리\n▶ 제품 보기', '', 1680000.00, 8400),
(17033, 1, '🎈 댕댕이 생일 파티 패키지', '', '✨ 케이크 + 고깔모자 + 가랜드 세트\n💎 단 한 번뿐인 소중한 날을 위해\n📌 지금 신청 시 파티 커튼 무료 증정\n▶ 파티 준비하기', '', 1070000.00, 5350),
(17034, 1, '🧊 쿨매트 여름 더위 탈출', '', '🔥 열대야에도 시원하게 꿀잠\n🎯 냉매 젤로 지속되는 시원함\n💰 선착순 특가 9,900원부터\n▶ 지금 득템', '', 460000.00, 2300),
(17035, 1, '🧥 프리미엄 레인코트 장마 대비', '', '✨ 비 오는 날 산책도 두렵지 않다\n📌 방수력 만점 + 반사판 부착\n🚀 장마철 전 미리 준비하세요\n▶ 레인코트 쇼핑', '', 1750000.00, 8750),
(17036, 1, '🏥 슬개골 탈구 예방 보호대', '', '🎯 다리 힘이 없는 아이들을 위해\n✨ 맞춤형 설계로 관절 지지력 강화\n📞 전문가 무료 상담 가능\n▶ 상세 정보 확인', '', 1140000.00, 5700),
(17037, 1, '🧹 털 제거 전용 청소기 특가', '', '💎 카펫 속 박힌 털까지 완벽 제거\n✨ 반려동물 가정 필수 가전\n💸 카드 할인 적용 시 월 9,900원\n▶ 렌탈 문의하기', '', 530000.00, 2650),
(17038, 1, '🥩 프리미엄 화식 배달 서비스', '', '🎯 신선한 재료로 갓 만든 한 끼\n✨ 사료보다 맛있는 영양 특식\n📌 첫 달 구독료 50% 반값\n▶ 정기배송 신청', '', 1820000.00, 9100),
(17039, 1, '🪞 반려동물 미용 자격증 과정', '', '✨ 사랑하는 아이를 직접 미용해봐요\n💎 실습 위주의 커리큘럼 + 취업 연계\n📌 수강료 최대 지원 이벤트\n▶ 교육 과정 보기', '', 1210000.00, 6050),
(17040, 1, '🧸 삑삑이 장난감 10종 세트', '', '🎯 질릴 틈 없는 다양한 구성\n✨ 튼튼한 캔버스 소재로 내구성 최고\n💰 세트 구매 시 1만원 할인\n▶ 장난감 세트 사기', '', 600000.00, 3000),
(17041, 1, '📦 유기견 후원 굿즈 뱃지 & 에코백', '', '✨ 수익금 전액이 유기견을 위해 사용\n💎 따뜻한 마음을 나누세요\n📌 리미티드 에디션 굿즈 출시\n▶ 후원 동참하기', '', 1890000.00, 9450),
(17042, 1, '🛁 욕조 매트 미끄럼 방지', '', '🎯 목욕 중 발 미끄러짐 방지\n✨ 강력한 흡착력 + 곰팡이 방지 소재\n🚀 오늘 주문하면 내일 도착\n▶ 목욕 용품 보기', '', 1280000.00, 6400),
(17043, 1, '👃 노령견 전용 영양 간식', '', '💎 소화가 잘 되는 부드러운 제형\n✨ 인지 능력 향상에 도움\n📌 수의사가 직접 설계한 포뮬러\n▶ 건강 간식 쇼핑', '', 670000.00, 3350),
(17044, 1, '👔 신사 댕댕이 넥타이 코디', '', '✨ 특별한 날, 격식 있는 코디\n📌 찍찍이로 간편하게 착용 가능\n💰 신상품 20% 기간 한정 할인\n▶ 스타일 보러가기', '', 1960000.00, 9800),
(17045, 1, '🚿 자동 급수기 깨끗한 물 공급', '', '🎯 흐르는 물로 음수량 폭발!\n✨ 3중 필터로 먼지 완벽 차단\n💸 특가 세일 중 ▶ 수량 얼마 없어요\n▶ 지금 클릭', '', 1350000.00, 6750),
(17046, 1, '🚪 펫 도어 방문 설치 서비스', '', '✨ 아이들이 자유롭게 이동하도록!\n📌 소음 방지 + 냉난방 유지 설계\n📞 서울/경기 무료 방문 견적\n▶ 설치 문의하기', '', 740000.00, 3700),
(17047, 1, '🧶 캣닢 인형 스트레스 해소 팍팍', '', '💎 냥이들이 환장하는 최상급 캣닢\n✨ 지루한 일상에 활력을!\n📌 3개 사면 1개 더 증정\n▶ 3+1 이벤트 보기', '', 130000.00, 650),
(17048, 1, '🏥 슬개골 강화 재활 클래스', '', '🎯 전문가와 함께하는 홈 재활 운동\n✨ 근육 강화로 수술 없이 예방하기\n📌 1:1 온라인 코칭권 포함\n▶ 클래스 신청', '', 1420000.00, 7100),
(17049, 1, '🥫 참치/연어 캔 24개입 박스 특가', '', '🔥 없어서 못 파는 기호성 끝판왕\n📌 유통기한 넉넉한 최신 제조 상품\n💰 박스 구매 시 개당 500원꼴\n▶ 박스 쟁여두기', '', 810000.00, 4050),
(17050, 1, '🎀 블링블링 인식표 제작', '', '✨ 우리 아이 이름을 보석처럼!\n💎 각인 무료 + 고급 가죽 스트랩\n📌 미아 방지 필수 아이템\n▶ 인식표 만들기', '', 200000.00, 1000);
