INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(17051, 1, '🐈 찰떡궁합 고양이 모래 1+1 세일', '', '✨ 먼지 날림 제로! 강력한 응고력\n💎 사막화 방지를 위한 집사 필품\n📌 오늘 주문 시 내일 아침 도착 🚀\n▶ 지금 쟁여두기', '', 1490000.00, 7450),
(17052, 1, '🦴 씹을수록 스트레스 풀리는 개껌', '', '🔥 100% 한우 가죽으로 만든 천연 껌\n🎯 치석 제거와 스트레스 해소를 동시에!\n💰 첫 구매 시 50% 할인 혜택\n▶ 바로 구매하기', '', 880000.00, 4400),
(17053, 1, '🐕 댕댕이 맞춤형 건강 검진권', '', '💎 노령견 필수! 종합 검진 패키지\n✨ 전문의 정밀 초음파 및 혈액 검사 포함\n📞 가까운 협력 병원 예약 지원\n▶ 검진권 신청하기', '', 270000.00, 1350),
(17054, 1, '👗 강아지 명품 룩북 신상 입고', '', '✨ 우리 아이도 패셔니스타 OOTD\n📌 럭셔리한 자수와 편안한 핏\n🔥 이번 주 신상 30% 한정 할인\n▶ 룩북 보러가기', '', 1560000.00, 7800),
(17055, 1, '🧼 펫 전용 저자극 귀 세정제', '', '🎯 가려움증 해결! 순한 성분 추출물\n💎 끈적임 없는 산뜻한 마무릿감\n📌 2개 세트 구매 시 전용 솜 증정\n▶ 제품 확인하기', '', 950000.00, 4750),
(17056, 1, '🏠 펫 리모델링 슬라이딩 도어', '', '✨ 아이들의 관절을 지켜주는 맞춤 설계\n📌 긁힘 방지 강화 코팅 마감\n📞 무료 방문 실측 및 견적 상담\n▶ 상담 신청 ▶', '', 340000.00, 1700),
(17057, 1, '🥩 100% 휴먼그레이드 자연화식', '', '🔥 사료 대신 신선한 고기와 야채\n🎯 알러지 걱정 없는 건강한 한 끼\n💰 정기 구독 첫 달 9,900원 이벤트\n▶ 지금 구독하기', '', 1630000.00, 8150),
(17058, 1, '📸 댕냥이 전용 셀프 사진관', '', '✨ 눈치 보지 말고 우리끼리 찰칵!\n💎 다양한 펫 전용 소품 및 의상 구비\n📌 전체 원본 데이터 무료 제공\n▶ 예약 신청하기', '', 1020000.00, 5100),
(17059, 1, '🧸 분리불안 완화 애착 인형', '', '🎯 주인의 체취를 담을 수 있는 설계\n✨ 혼자 있는 시간도 외롭지 않아요\n🚀 로켓 배송으로 빠르게 만나보세요\n▶ 상세 보기', '', 410000.00, 2050),
(17060, 1, '🏥 반려동물 장례 서비스 사전 예약', '', '💎 마지막 가는 길, 최고의 예우로\n✨ 24시 상담 및 전국 지점 보유\n📌 사전 예약 시 추모 굿즈 제작\n▶ 무료 상담 받기', '', 1700000.00, 8500),
(17061, 1, '🥤 휴대용 산책 물통 단독 특가', '', '🔥 버튼 하나로 물 급여 완료!\n📌 가방에 쏙 들어가는 콤팩트 사이즈\n💰 단 3일간만 5,900원 무배\n▶ 득템하러 가기', '', 1090000.00, 5450),
(17062, 1, '🧘‍♂️ 댕댕이와 함께하는 요가 클래스', '', '✨ 교감을 통한 스트레스 완화\n🎯 초보자도 쉽게 따라 하는 동작\n📌 이번 주 토요일 원데이 특가\n▶ 클래스 신청', '', 480000.00, 2400),
(17063, 1, '📦 펫 전용 자동 배변 처리기', '', '💎 냄새 걱정 끝! 자동 밀봉 시스템\n✨ 집사의 삶의 질이 수직 상승합니다\n📞 렌탈 서비스 월 1만원대\n▶ 지금 신청', '', 1770000.00, 8850),
(17064, 1, '🥗 고양이 전용 캣그라스 키트', '', '🎯 헤어볼 배출을 돕는 신선한 새싹\n✨ 흙 없이 수경재배로 깔끔하게\n📌 아이들도 좋아하는 간식 대용\n▶ 키트 사러가기', '', 1160000.00, 5800),
(17065, 1, '🎒 프리미엄 백팩형 이동장', '', '💎 어깨가 편안한 인체공학적 설계\n✨ 대중교통 이용 시 필수 아이템\n🔥 신규 가입 시 1만원 즉시 할인\n▶ 제품 보기', '', 550000.00, 2750),
(17066, 1, '📒 반려동물 건강 수첩 나눔', '', '✨ 접종 기록부터 사료 체크까지\n📌 선착순 500명 무료 증정 이벤트\n💰 배송비만 내고 받아가세요\n▶ 수첩 신청하기', '', 1840000.00, 9200),
(17067, 1, '🛁 펫 전용 스파 입욕제 탄산포', '', '🎯 각질 제거와 모질 개선을 한 번에\n✨ 향긋한 라벤더 향으로 힐링 타임\n📌 목욕 거부 아이들에게 강력 추천\n▶ 스파 용품 보기', '', 1230000.00, 6150),
(17068, 1, '📺 펫 전용 채널 정기 결제권', '', '💎 집 비울 때 보여주면 안정감 UP\n✨ 심리학자가 설계한 시청각 콘텐츠\n💸 첫 달 0원 체험 서비스 중\n▶ 무료 체험 신청', '', 620000.00, 3100),
(17069, 1, '🍗 수제 오리 안심 육포 500g', '', '🔥 고단백 저지방 최고의 영양 간식\n🎯 무첨가물, 오직 원물 100%\n💰 대용량 기획 구성 40% 세일\n▶ 바로 구매', '', 1910000.00, 9550),
(17070, 1, '🧤 털 제거 매직 장갑 1+1', '', '✨ 빗질만 해도 죽은 털이 쑥쑥!\n📌 마사지 효과로 아이들도 좋아해요\n🚀 빠른 배송 + 추가 할인 혜택\n▶ 지금 클릭', '', 1300000.00, 6500),
(17071, 1, '🏥 고양이 신부전 예방 영양제', '', '🎯 나이 든 고양이를 위한 필수 선택\n✨ 신장 기능을 보조하는 핵심 성분\n📞 수의사 상담 후 급여 추천\n▶ 영양제 확인', '', 690000.00, 3450),
(17072, 1, '👔 펫 웨딩 수트 & 드레스', '', '💎 특별한 날, 아이들도 주인공처럼\n✨ 맞춤 제작으로 편안한 착용감\n📌 웨딩 시즌 한정 소품 증정\n▶ 스타일 보기', '', 1980000.00, 9900),
(17073, 1, '🧼 항균 펫 전용 물티슈 대용량', '', '🎯 산책 후 발바닥 슥슥 간편하게\n✨ 유해 성분 0% 안심하고 사용\n💰 10팩 박스 구매 시 역대급 할인\n▶ 박스 구매', '', 1370000.00, 6850),
(17074, 1, '🧊 여름용 쿨 조끼 야외 활동 필수', '', '🔥 체감 온도 -5도! 시원한 산책\n📌 물만 적셔서 입히면 끝\n⚡ 오늘 주문 시 내일 바로 도착\n▶ 쿨조끼 구매', '', 760000.00, 3800),
(17075, 1, '🧶 수제 뜨개 장난감 공구', '', '✨ 엄마의 마음으로 한 땀 한 땀\n💎 솜 대신 바스락 소리 나는 소재\n📌 선착순 50명 핸드메이드 굿즈\n▶ 공구 참여하기', '', 150000.00, 750),
(17076, 1, '🚪 고양이 캣휠 운동 부족 해결', '', '🎯 우다다 본능을 마음껏 발산!\n✨ 저소음 베어링으로 밤에도 조용히\n💸 무이자 할부 혜택 진행 중\n▶ 캣휠 보러가기', '', 1440000.00, 7200),
(17077, 1, '🦷 먹는 치약 겔타입 50% 세일', '', '🔥 칫솔질 싫어하는 아이들 주목!\n📌 핥기만 해도 치석이 제거됩니다\n💰 2개 구매 시 전용 칫솔 증정\n▶ 지금 득템', '', 830000.00, 4150),
(17078, 1, '🧴 펫 전용 향수 알러지 프리', '', '✨ 꼬질꼬질한 냄새는 이제 그만\n💎 은은한 비누 향기로 기분 전환\n📌 피부 자극 테스트 완료\n▶ 향수 쇼핑', '', 220000.00, 1100),
(17079, 1, '🧺 라탄 펫 하우스 감성 소품', '', '✨ 거실 어디에 둬도 예쁜 디자인\n📌 통풍이 잘 되어 여름에도 쾌적\n💸 한정 수량 단독 30% 특가\n▶ 감성템 확인', '', 1510000.00, 7550),
(17080, 1, '🥩 무항생제 생식 패키지 입문', '', '🎯 자연 그대로의 영양을 전달하세요\n✨ 모질 개선 및 눈물 자국 완화\n📞 생식 가이드북 무료 증정\n▶ 입문 세트 보기', '', 900000.00, 4500),
(17081, 1, '🩺 펫 비만 관리 1:1 컨설팅', '', '💎 우리 아이 체중, 건강의 적입니다\n✨ 맞춤 식단부터 운동 계획까지\n📌 지금 신청 시 식단 일기 증정\n▶ 컨설팅 신청', '', 290000.00, 1450),
(17082, 1, '🎀 큐티 뽀짝 리본 목걸이', '', '✨ 미모 포텐 터지는 포인트 아이템\n📌 가벼운 무게로 불편함 제로\n💰 3개 이상 구매 시 배송비 무료\n▶ 코디하기', '', 1580000.00, 7900),
(17083, 1, '🛁 자동 목욕 기기 렌탈 시작', '', '🎯 손 대지 않고 깨끗하게 샤워!\n✨ 드라이 기능까지 한 번에 해결\n📞 월 2만원대 프리미엄 관리\n▶ 렌탈 문의하기', '', 970000.00, 4850),
(17084, 1, '🦟 펫 전용 해충 방지 클립', '', '🔥 산책 시 진드기 완벽 차단!\n📌 천연 오일 성분으로 무해합니다\n🚀 산책 가기 전 필수 준비물\n▶ 해충 방지템 사기', '', 360000.00, 1800),
(17085, 1, '🧀 강아지 전용 치즈 간식 박스', '', '✨ 칼슘 가득! 쫄깃한 식감\n💎 저염 설계로 건강까지 챙겼어요\n📌 낱개 포장으로 위생적인 보관\n▶ 간식 박스 확인', '', 1650000.00, 8250),
(17086, 1, '🏥 펫 구급상자 가정 비치용', '', '🎯 비상시 당황하지 말고 챙기세요\n✨ 소독약부터 붕대까지 풀세트\n💰 지금 구매 시 응급처치 가이드 증정\n▶ 구급상자 보기', '', 1040000.00, 5200),
(17087, 1, '🛋️ 펫 전용 스크래처 쇼파형', '', '✨ 냥이들의 뜯고 맛보는 즐거움\n📌 먼지 적은 고밀도 골판지 사용\n💸 오픈 기념 1+1 이벤트\n▶ 스크래처 쇼핑', '', 430000.00, 2150),
(17088, 1, '📸 우리 아이 배경화면 제작 서비스', '', '💎 세상에 단 하나뿐인 일러스트\n✨ 사진만 보내주면 1시간 내 완성\n📌 폰케이스 제작 추가 할인\n▶ 제작 의뢰하기', '', 1720000.00, 8600),
(17089, 1, '👟 강아지 산책 신발 4짝 세트', '', '🎯 뜨거운 아스팔트로부터 발바닥 보호\n✨ 미끄럼 방지 처리로 안전하게\n📌 다양한 사이즈 보유\n▶ 사이즈 체크하기', '', 1110000.00, 5550),
(17090, 1, '🧴 펫 전용 탈취제 대용량 4L', '', '🔥 오줌 냄새, 체취 완벽 박멸\n📌 은은한 숲속 향기로 리프레시\n💰 가성비 끝판왕 대용량 기획\n▶ 바로 확인', '', 500000.00, 2500),
(17091, 1, '🎒 반려동물 카시트 안전벨트 포함', '', '✨ 차 안에서도 안전하고 편안하게\n💎 푹신한 쿠션감으로 멀미 방지\n📌 전 차종 호환 가능 설계\n▶ 카시트 구경하기', '', 1790000.00, 8950),
(17092, 1, '🦴 노령견 관절 보충제 골드', '', '🎯 걷는 게 힘들어 보인다면?\n✨ 글루코사민 고함량 처방\n📞 3개월 복용 시 효과 보장제\n▶ 영양제 상담', '', 1180000.00, 5900),
(17093, 1, '🧤 펫 전용 털 말리기 장갑', '', '✨ 드라이 시간을 절반으로 단축!\n📌 초극세사 소재로 강력한 흡수력\n💰 오늘만 9,900원 한정 수량\n▶ 드라이 장갑 사기', '', 570000.00, 2850),
(17094, 1, '🐱 캣타워 전용 해먹 추가 키트', '', '💎 꿀잠 자는 냥이들을 위한 선물\n✨ 튼튼한 지지력 + 부드러운 천\n📌 기존 캣타워 완벽 호환\n▶ 해먹 추가하기', '', 1860000.00, 9300),
(17095, 1, '🏥 실시간 펫 병원 예약 플랫폼', '', '🎯 기다리지 말고 바로 진료받으세요\n✨ 전국 2,000개 병원 제휴 완료\n📌 첫 예약 시 포인트 5,000점\n▶ 앱 다운로드', '', 1250000.00, 6250),
(17096, 1, '👕 펫 커스텀 티슈 티셔츠 제작', '', '✨ 아이 얼굴이 들어간 특별한 옷\n📌 100% 면 소재로 부드럽게\n💸 가족 세트 구매 시 추가 할인\n▶ 커스텀 하기', '', 640000.00, 3200),
(17097, 1, '🧶 실타래 터그 놀이 세트', '', '🎯 활동량 많은 댕댕이 필수템\n✨ 치아 건강에도 도움을 줍니다\n📌 튼튼한 면사로 오래오래\n▶ 장난감 보기', '', 1930000.00, 9650),
(17098, 1, '🥛 펫 전용 락토프리 우유 10팩', '', '🔥 소화 잘 되는 맛있는 간식\n📌 비타민과 타우린 추가 배합\n💰 편의점보다 싼 최저가 도전\n▶ 우유 쟁여두기', '', 1320000.00, 6600),
(17099, 1, '🖼️ 반려동물 팝아트 초상화 클래스', '', '✨ 직접 그리는 우리 아이 얼굴\n💎 초보자도 가능한 가이드라인 제공\n📌 재료비 포함 원데이 특가\n▶ 클래스 예약', '', 710000.00, 3550),
(17100, 1, '🛁 펫 전용 타월 초대형 사이즈', '', '🎯 한 번에 싹 닦이는 놀라운 흡수력\n✨ 건조기 돌려도 변형 없는 소재\n🚀 오늘 사면 내일 바로 사용\n▶ 타월 구매하기', '', 100000.00, 500);
