INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(17101, 1, '🐈 캣타워 전용 스크래치 리필 패드', '', '✨ 닳고 닳은 스크래처, 새것처럼 교체하세요\n💎 고밀도 골판지로 먼지 발생 최소화\n📌 지금 구매 시 1+1 추가 증정 이벤트\n▶ 리필 쟁여두기', '', 1390000.00, 6950),
(17102, 1, '🐕 대형견 전용 튼튼한 가슴줄 하네스', '', '🔥 당기는 힘이 강한 아이도 안심!\n🎯 체중 분산 설계로 기도 압박 제로\n⚡ 오늘만 이 가격, 선착순 50명 할인\n▶ 튼튼 하네스 보기', '', 780000.00, 3900),
(17103, 1, '🥩 무염 북어 트릿 기력 회복 특식', '', '💎 입맛 없는 아이를 위한 최고의 선택\n✨ 저염 공정으로 건강하게 담았습니다\n📌 영양 만점 수제 간식 시리즈\n▶ 지금 주문하기', '', 170000.00, 850),
(17104, 1, '🏠 강아지 전용 원목 침대 프레임', '', '✨ 거실 인테리어와 찰떡궁합!\n📌 최고급 소나무 원목 사용 + 친환경 도색\n💸 신규 가입 10% 추가 할인 혜택\n▶ 가구 구경하기', '', 1460000.00, 7300),
(17105, 1, '✂️ 펫 미용 전용 안전 가위 세트', '', '🎯 집에서 직접 해주는 안심 미용\n💎 끝이 둥글어 초보자도 다칠 염려 없어요\n🚀 내일 도착 보장 배송 서비스\n▶ 미용 세트 보기', '', 850000.00, 4250),
(17106, 1, '🏥 펫 전용 유산균 가루 타입', '', '✨ 장 건강이 면역력의 핵심입니다\n📌 10억 보장 균수 + 기호성 좋은 맛\n📞 수의사가 추천하는 필수 영양제\n▶ 유산균 보러가기', '', 240000.00, 1200),
(17107, 1, '🦴 오리 목뼈 수제 간식 1kg', '', '🔥 스트레스 해소와 치석 제거를 한 번에\n🎯 국내산 오리만 사용하여 믿을 수 있어요\n💰 대용량 기획팩 역대급 가성비\n▶ 바로 구매하기', '', 1530000.00, 7650),
(17108, 1, '✈️ 반려동물 동반 호텔 숙박권', '', '🐕 사랑하는 아이와 함께하는 호캉스\n✨ 전용 침대 및 어메니티 완비\n📌 레이트 체크아웃 무료 이벤트 진행\n▶ 호텔 예약하기', '', 920000.00, 4600),
(17109, 1, '🧼 펫 풋 샴푸 거품형 세정제', '', '💎 산책 후 물 없이 간편하게 슥삭\n✨ 자연 유래 성분으로 보습까지 완벽\n🎯 전용 브러쉬 일체형으로 편리함 UP\n▶ 구매하러 가기', '', 310000.00, 1550),
(17110, 1, '🎡 원목 캣폴 수직 공간 확보', '', '🔥 좁은 집도 오케이! 층간 소음 방지\n📌 튼튼한 내구성과 모던한 디자인\n💰 한정 수량 40% 타임 세일 중\n▶ 캣폴 쇼핑하기', '', 1600000.00, 8000),
(17111, 1, '📺 펫 전용 자동 장난감 로봇', '', '✨ 집 비울 때 혼자 노는 똑똑한 친구\n📌 불규칙한 움직임으로 호기심 자극\n🎯 앱으로 실시간 조종 가능\n▶ 스마트 토이 보기', '', 990000.00, 4950),
(17112, 1, '🧶 삑삑이 공 장난감 랜덤 박스', '', '💎 어떤 공이 올까? 설레는 간식 시간\n✨ 튼튼한 고무 소재로 물어뜯어도 안심\n🚀 지금 주문 시 당일 발송 완료\n▶ 랜덤 박스 구매', '', 380000.00, 1900),
(17113, 1, '🥤 휴대용 펫 물병 500ml', '', '🎯 원터치 물 공급 + 남은 물 회수 기능\n📌 누수 방지 실리콘 패킹 적용\n💸 1+1 특별 구성으로 친구랑 나눠요\n▶ 물병 확인하기', '', 1670000.00, 8350),
(17114, 1, '📸 펫 프로필 촬영 전문 스튜디오', '', '✨ 생애 가장 아름다운 순간을 기록하세요\n💎 반려동물 전문 작가 직접 촬영\n📌 액자 제작 시 원본 데이터 무료\n▶ 예약 문의하기', '', 1060000.00, 5300),
(17115, 1, '📚 고양이 행동 교정 백과사전', '', '🎯 우리 냥이는 왜 그럴까? 명쾌한 해답\n✨ 전문가가 알려주는 꿀팁 대방출\n💰 신간 출시 기념 무료 배송 혜택\n▶ 도서 자세히 보기', '', 450000.00, 2250),
(17116, 1, '🦷 고양이 전용 치약 + 칫솔 세트', '', '🔥 구내염 예방을 위한 하루 1분 투자\n📌 닭고기 맛으로 거부감 없이 양치질\n⚡ 한정 수량 30% 즉시 할인 중\n▶ 치과 세트 구매', '', 1740000.00, 8700),
(17117, 1, '🧺 펫 전용 쿨링 방석 여름 필수', '', '✨ 닿는 순간 시원해지는 냉감 소재\n💎 세탁기 사용 가능해서 위생적이에요\n📌 열 많은 아이들에게 강력 추천\n▶ 쿨링템 보기', '', 1130000.00, 5650),
(17118, 1, '🍗 수제 연어 큐브 영양 간식', '', '🎯 풍부한 오메가3로 피모 건강 개선\n✨ 한 입 크기로 훈련용 간식에 딱!\n💰 3봉 구매 시 1봉 더 드립니다\n▶ 3+1 혜택받기', '', 520000.00, 2600),
(17119, 1, '🧥 겨울 신상 강아지 니트 스웨터', '', '💎 따뜻함과 스타일을 동시에 잡으세요\n✨ 쫀쫀한 신축성으로 입고 벗기 편함\n📌 무신사 펫 베스트 아이템 등극\n▶ 니트 구경하기', '', 1810000.00, 9050),
(17120, 1, '🏃‍♂️ 펫 피트니스 볼 밸런스 운동', '', '🔥 코어 근육 강화로 관절 질환 예방\n🎯 집에서 즐기는 건강한 놀이 시간\n💸 지금 구매 시 펌프 무료 증정\n▶ 피트니스 보기', '', 1200000.00, 6000),
(17121, 1, '🧴 펫 전용 탈취 미스트 무향', '', '✨ 냄새 원인균을 직접 제거합니다\n💎 향에 예민한 아이들을 위한 무향\n📌 식물 추출 성분으로 안심 분사\n▶ 미스트 구매', '', 590000.00, 2950),
(17122, 1, '🥣 강아지 경사 식탁 높이 조절', '', '📌 소화 불량 방지를 위한 최적의 각도\n✨ 성장 단계에 맞춰 높이 조절 가능\n💸 런칭 기념 특가 세일 진행 중\n▶ 식탁 보러가기', '', 1880000.00, 9400),
(17123, 1, '🎒 우주선 투명 캣 캐리어', '', '🎯 밖을 보며 안심하는 신개념 이동장\n✨ 통기성 우수 + 가벼운 하드쉘 구조\n🚀 오늘 사면 내일 바로 외출 가능\n▶ 이동장 쇼핑', '', 1270000.00, 6350),
(17124, 1, '🥬 동결건조 과일 칩 세트', '', '💎 사과, 바나나, 딸기 영양 그대로\n✨ 원물 외 아무것도 넣지 않았습니다\n📌 다이어트 중인 아이에게 추천\n▶ 과일칩 사러가기', '', 660000.00, 3300),
(17125, 1, '🧬 펫 건강 유전자 검사 서비스', '', '🎯 미리 알고 대처하는 유전병 위험\n✨ 집에서 1분 만에 샘플 채취 완료\n📞 결과 리포트 평생 소장 가능\n▶ 검사 키트 신청', '', 1950000.00, 9750),
(17126, 1, '🪑 거실용 펫 스텝 3단 슬라이드', '', '✨ 높은 소파도 안전하게 오르내려요\n📌 미끄럼 방지 커버 + 고탄성 스펀지\n💰 한정 수량 특가 19,900원\n▶ 펫스텝 보기', '', 1340000.00, 6700),
(17127, 1, '🚑 야간 응급 동물병원 매칭 앱', '', '🎯 새벽에도 당황하지 말고 클릭!\n✨ 현재 진료 중인 병원 실시간 확인\n📌 앱 결제 시 진료비 추가 할인\n▶ 앱 설치하기', '', 730000.00, 3650),
(17128, 1, '🐟 연어 육포 프리미엄 라인', '', '💎 최상급 연어로 만든 명품 간식\n✨ 인공 색소 및 방부제 절대 사절\n💸 2+1 이벤트 선착순 마감 임박\n▶ 프리미엄 구매', '', 120000.00, 600),
(17129, 1, '🧣 집사랑 댕댕이랑 커플 목도리', '', '✨ 겨울 산책의 완성은 커플룩!\n📌 부드러운 핸드메이드 감성 니트\n💰 커플 세트 구매 시 사은품 증정\n▶ 커플템 보러가기', '', 1410000.00, 7050),
(17130, 1, '🧼 펫 발 전용 수분 보습 밤', '', '🎯 거칠어진 발바닥을 촉촉하게!\n✨ 핥아도 무해한 천연 성분 밤\n📌 휴대용 스틱 타입으로 간편함\n▶ 보습 밤 쇼핑', '', 800000.00, 4000),
(17131, 1, '⛺ 실내용 펫 인디언 텐트', '', '💎 아늑한 나만의 공간을 선물하세요\n✨ 세탁 가능한 캔버스 천 사용\n💸 감성 인테리어 20% 세일\n▶ 텐트 구경하기', '', 190000.00, 950),
(17132, 1, '🍼 초유 성분 함유 영양 우유', '', '🎯 기력 회복이 필요한 아이 필수템\n✨ 눈 건강을 위한 타우린 배합\n📌 낱개 포장으로 위생적인 보관\n▶ 우유 주문하기', '', 1480000.00, 7400),
(17133, 1, '🎈 펫 파티 선글라스 & 액세서리', '', '✨ 인스타 감성샷 필수 소품들!\n💎 귀여움 한도 초과 보장합니다\n📌 지금 구매 시 파티 고깔 증정\n▶ 소품 쇼핑하기', '', 870000.00, 4350),
(17134, 1, '🧊 펫 아이스 스카프 야외용', '', '🔥 산책 중 열사병 예방 필수 아이템\n🎯 아이스팩 삽입형으로 강력한 쿨링\n💰 특가 세일 7,900원부터 시작\n▶ 아이스템 확인', '', 260000.00, 1300),
(17135, 1, '🧥 올인원 바람막이 사계절용', '', '✨ 진드기 차단부터 생활 방수까지\n📌 가벼운 소재로 활동성 극대화\n🚀 당일 발송 가능 재고 확보\n▶ 바람막이 구매', '', 1550000.00, 7750),
(17136, 1, '🏥 노령견 전용 워킹 보조기', '', '🎯 뒷다리 힘이 약해진 아이들을 위해\n✨ 맞춤형 사이즈 조절 기능 탑재\n📞 전문 상담원과 사이즈 상의하세요\n▶ 보조기 보기', '', 940000.00, 4700),
(17137, 1, '🧹 펫 털 제거 돌돌이 세트', '', '💎 한 번 밀면 옷의 털이 사라져요\n✨ 반려동물 가정의 영원한 동반자\n💸 리필 10개입 박스 특가 판매\n▶ 돌돌이 구매', '', 330000.00, 1650),
(17138, 1, '🥩 펫 수제 만두 영양 특식', '', '🎯 특별한 날, 건강한 만두 한 끼\n✨ 사람이 먹는 재료로 정성껏 빚음\n📌 냉동 보관으로 신선하게 배송\n▶ 특식 주문하기', '', 1620000.00, 8100),
(17139, 1, '🪞 펫 미용 원데이 클래스 모집', '', '✨ 위생 미용, 이제 직접 해보세요\n💎 실습용 마네킹 제공 + 도구 대여\n📌 선착순 10명 수강료 할인\n▶ 클래스 등록', '', 1010000.00, 5050),
(17140, 1, '🧸 튼튼한 면 로프 터그 장난감', '', '🎯 스트레스 풀리는 신나는 놀이\n✨ 치아 사이 이물질 제거 효과\n💰 세트 구매 시 장난감 1종 추가\n▶ 장난감 세트 사기', '', 400000.00, 2000),
(17141, 1, '📦 유기견 돕기 기부 캘린더', '', '✨ 귀여운 아이들의 모습이 가득\n💎 판매 수익금 전액 기부됩니다\n📌 2026년 한정판 캘린더 출시\n▶ 기부 동참하기', '', 1690000.00, 8450),
(17142, 1, '🛁 펫 전용 샴푸 브러쉬 세트', '', '🎯 죽은 털 제거와 샴푸를 동시에\n✨ 실리콘 돌기로 부드러운 마사지\n🚀 오늘 주문 시 내일 도착 보장\n▶ 목욕 용품 보기', '', 1080000.00, 5400),
(17143, 1, '👃 노즈워크 담요 대형 사이즈', '', '💎 분리불안 완화에 최고의 선물\n✨ 다양한 간식 포켓으로 난이도 조절\n📌 세탁이 간편한 폴라폴리스 소재\n▶ 담요 확인하기', '', 470000.00, 2350),
(17144, 1, '👔 펫 전용 체크 남방 셔츠', '', '✨ 댄디한 댕댕이로 변신 완료!\n📌 100% 면 소재로 자극 제로\n💰 신상품 20% 기간 한정 세일\n▶ 셔츠 보러가기', '', 1760000.00, 8800),
(17145, 1, '🚿 무선 자동 급수기 저소음', '', '🎯 전선 걱정 없이 어디든 배치 가능\n✨ 고양이 음수량 늘리기 프로젝트\n💸 선착순 100명 필터 추가 증정\n▶ 급수기 구매', '', 1150000.00, 5750),
(17146, 1, '🚪 자석식 펫 방충망 설치형', '', '✨ 베란다 출입을 자유롭고 안전하게\n📌 튼튼한 메쉬망으로 찢어짐 방지\n📞 간단한 자가 설치 가능 상품\n▶ 방충망 보기', '', 540000.00, 2700),
(17147, 1, '🧶 캣닢 가득 물고기 인형', '', '💎 냥이들이 물고 빨아도 튼튼해요\n✨ 최상급 국산 캣닢 사용 완료\n📌 1+1 이벤트로 두 마리도 거뜬\n▶ 냥이 장난감 사기', '', 1830000.00, 9150),
(17148, 1, '🏥 슬개골 보호 무릎 밴드', '', '🎯 점프를 즐기는 아이들 필수\n✨ 관절을 지지하여 통증을 완화\n📌 지금 구매 시 물리치료 가이드 증정\n▶ 밴드 보러가기', '', 1220000.00, 6100),
(17149, 1, '🥫 참치 무스 파우치 대용량팩', '', '🔥 기호성 보장! 입맛 살리는 무스\n📌 비타민과 미네랄이 풍부해요\n💰 박스 구매 시 개당 최저가 실현\n▶ 파우치 쟁여두기', '', 610000.00, 3050),
(17150, 1, '🎀 럭셔리 네임택 골드 각인', '', '✨ 우리 아이의 이름표를 특별하게\n💎 24K 골드 도금 + 미아방지 각인\n📌 주문 제작 상품으로 정성 가득\n▶ 네임택 만들기', '', 1900000.00, 9500);
