INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(17151, 1, '🐈 벤토나이트 모래 6kg x 3봉', '', '✨ 먼지 걱정 없는 쾌적한 화장실!\n💎 강력한 응고력으로 청소가 쉬워져요\n📌 지금 주문 시 전용 삽 증정 🎁\n▶ 모래 쟁여두기', '', 1290000.00, 6450),
(17152, 1, '🐕 튼튼한 자동 리드줄 5m 특가', '', '🔥 밤에도 안전한 반사 테이프 적용\n🎯 부드러운 핸들링으로 산책이 즐거워요\n⚡ 오늘만 40% 한정 세일 진행 중!\n▶ 리드줄 사러가기', '', 680000.00, 3400),
(17153, 1, '🥩 무방부제 한우 간 육포 간식', '', '💎 철분 가득! 눈물 자국 완화에 도움\n✨ 국내산 원물로 정성껏 말렸습니다\n📌 영양 가득 수제 간식 시리즈\n▶ 지금 주문하기', '', 1970000.00, 9850),
(17154, 1, '🏠 원목 펫 하우스 감성 가구', '', '✨ 거실 분위기를 살리는 모던 디자인\n📌 사계절 사용 가능한 리버시블 쿠션 포함\n💸 신규 가입 시 10% 추가 할인\n▶ 하우스 구경하기', '', 1360000.00, 6800),
(17155, 1, '✂️ 펫 발톱 깎이 무혈 안심 설계', '', '🎯 혈관을 보호하는 안전 가이드 장착\n💎 초보 집사도 쉽고 빠르게 깎아요\n🚀 오늘 사면 내일 바로 도착\n▶ 안심 가위 보기', '', 750000.00, 3750),
(17156, 1, '🏥 강아지 관절 영양제 대용량', '', '✨ 슬개골 건강, 미리미리 챙겨주세요\n📌 콘드로이친 + 글루코사민 고함량\n📞 수의사가 강력 추천하는 스테디셀러\n▶ 영양제 보러가기', '', 140000.00, 700),
(17157, 1, '🦴 천연 라텍스 삑삑이 장난감', '', '🔥 물어뜯어도 안전한 천연 고무 소재\n🎯 스트레스 해소와 치아 관리를 한 번에\n💰 3개 세트 구매 시 1만원 할인\n▶ 바로 구매하기', '', 1430000.00, 7150),
(17158, 1, '✈️ 반려동물 동반 제주 패키지', '', '🐕 댕댕이랑 비행기 타고 제주도로!\n✨ 전용 렌터카 + 펫 프렌들리 숙소\n📌 지금 예약 시 유기농 간식 세트 증정\n▶ 여행 예약하기', '', 820000.00, 4100),
(17159, 1, '🧼 펫 전용 샴푸 & 린스 올인원', '', '💎 저자극 성분으로 민감한 피부 보호\n✨ 은은한 파우더 향이 7일간 지속\n🎯 펌프형 용기로 사용이 더 편리해요\n▶ 제품 확인하기', '', 210000.00, 1050),
(17160, 1, '🎡 고양이 수직 공간 캣타워 특가', '', '🔥 층간 소음 방지! 튼튼한 지지력\n📌 스크래처 기둥이 포함된 알찬 구성\n💰 역대급 50% 타임 세일 중\n▶ 캣타워 쇼핑하기', '', 1500000.00, 7500),
(17161, 1, '📺 스마트 펫 피더 자동 급식기', '', '✨ 집 밖에서도 스마트폰으로 급여!\n📌 정확한 양 조절로 비만 예방 가능\n🎯 선착순 50명 전용 식기 증정\n▶ 제품 보기', '', 890000.00, 4450),
(17162, 1, '🧶 고양이 낚싯대 장난감 5종', '', '💎 냥이들의 사냥 본능을 깨우세요\n✨ 깃털, 방울, 리본 등 다양한 구성\n🚀 오늘 주문하면 내일 바로 놀아줌\n▶ 장난감 구매', '', 280000.00, 1400),
(17163, 1, '🥤 펫 전용 비타민 워터 500ml', '', '🎯 음수량 늘리기 프로젝트 필수템\n📌 전해질 보충으로 기력 회복 도움\n💸 10개입 박스 구매 시 무료배송\n▶ 워터 확인하기', '', 1570000.00, 7850),
(17164, 1, '📸 펫 야외 스냅 촬영 이벤트', '', '✨ 따스한 햇살 아래 인생샷 남기기\n💎 전문 작가가 동행하는 산책 촬영\n📌 촬영권 구매 시 보정본 10장 추가\n▶ 예약 문의하기', '', 960000.00, 4800),
(17165, 1, '📚 반려동물 수제 간식 레시피북', '', '🎯 내 아이에게 직접 만들어주는 건강함\n✨ 50가지 쉽고 맛있는 레시피 수록\n💰 출간 기념 독점 20% 할인\n▶ 도서 자세히 보기', '', 350000.00, 1750),
(17166, 1, '🦷 고양이 구강 관리 젤타입 치약', '', '🔥 칫솔질 없이 바르기만 하세요\n📌 치태 제거 및 구취 억제 효과 탁월\n⚡ 한정 수량 단독 특가 진행 중\n▶ 치약 세트 구매', '', 1640000.00, 8200),
(17167, 1, '🧺 펫 전용 전기 온열 매트', '', '✨ 추운 겨울, 아이들에게 따뜻함을\n💎 7단계 온도 조절 + 자동 전원 차단\n📌 노령견/노령묘 강력 추천템\n▶ 온열 매트 보기', '', 1030000.00, 5150),
(17168, 1, '🍗 동결건조 북어 트릿 100g', '', '🎯 영양 손실 최소화! 원물 그대로\n✨ 물에 불려주면 음수량 확보에도 최고\n💰 2개 사면 1개 더 드립니다\n▶ 2+1 혜택받기', '', 420000.00, 2100),
(17169, 1, '🧥 강아지 퀼팅 패딩 조끼 신상', '', '💎 영하의 날씨에도 따뜻한 산책\n✨ 가볍고 활동적인 크롭 디자인\n📌 무신사 펫 인기 랭킹 상위권\n▶ 패딩 구경하기', '', 1710000.00, 8550),
(17170, 1, '🏃‍♂️ 펫 전용 밸런스 패드 운동', '', '🔥 뒷다리 근육 강화와 균형 감각 발달\n🎯 슬개골 탈구 예방 홈트레이닝\n💸 지금 구매 시 운동 가이드북 증정\n▶ 피트니스 보기', '', 1100000.00, 5500),
(17171, 1, '🧴 펫 귀 세정제 저자극 워터', '', '✨ 귀 냄새와 가려움증 한 번에 해결\n💎 끈적임 없는 순한 성분 추출물\n📌 정기 구독 시 15% 상시 할인\n▶ 세정제 구매', '', 490000.00, 2450),
(17172, 1, '🥣 세라믹 펫 식기 세트 2구', '', '📌 턱드름 방지! 위생적인 도자기 재질\n✨ 안정감 있는 무게로 밀림 방지\n💸 오픈 기념 30% 선착순 세일\n▶ 식기 보러가기', '', 1780000.00, 8900),
(17173, 1, '🎒 확장형 펫 백팩 이동장', '', '🎯 안에서 넓게 펴지는 신개념 공간\n✨ 여행이나 병원 갈 때 최고의 선택\n🚀 지금 주문 시 당일 발송 완료\n▶ 이동장 쇼핑', '', 1170000.00, 5850),
(17174, 1, '🥬 펫 전용 과채 주스 10팩', '', '💎 사과와 당근의 신선함 그대로\n✨ 식이섬유가 풍부해 배변 활동 도움\n📌 휴대가 간편한 파우치 타입\n▶ 주스 사러가기', '', 560000.00, 2800),
(17175, 1, '🧬 펫 알러지 검사 키트 출시', '', '🎯 가려움증 원인을 집에서 찾으세요\n✨ 60가지 주요 알러지 항목 분석\n📞 검사 결과 모바일 리포트 제공\n▶ 검사 신청하기', '', 1850000.00, 9250),
(17176, 1, '🪑 거실용 펫 계단 원목 스텝', '', '✨ 침대나 소파 아래 필수 아이템\n📌 튼튼한 내구성과 논슬립 패드 적용\n💰 오늘만 특가 29,900원 한정\n▶ 펫계단 보기', '', 1240000.00, 6200),
(17177, 1, '🚑 24시간 비대면 수의사 상담 앱', '', '🎯 급할 때 물어보세요! 실시간 답변\n✨ 사진/영상 공유로 정확한 상담\n📌 첫 상담료 0원 이벤트 진행 중\n▶ 앱 설치하기', '', 630000.00, 3150),
(17178, 1, '🐟 연어 껍질 껌 피모 개선 전용', '', '💎 콜라겐 듬뿍! 윤기 나는 털 관리\n✨ 알러지 걱정 없는 생선 베이스\n💸 3팩 구매 시 1팩 추가 증정\n▶ 껌 구매하기', '', 1920000.00, 9600),
(17179, 1, '🧣 집사랑 커플 후드티 세트', '', '✨ 산책길 시선 강탈! 커플 룩 완성\n📌 기모 안감으로 겨울에도 포근하게\n💰 세트 구매 시 적립금 10% 지급\n▶ 커플템 보러가기', '', 1310000.00, 6550),
(17180, 1, '🧼 펫 발바닥 보호 왁스 스틱', '', '🎯 거친 땅으로부터 발바닥 패드 보호\n✨ 천연 밀랍 성분으로 먹어도 안심\n📌 산책 전후 슥슥 발라주세요\n▶ 보호 왁스 쇼핑', '', 700000.00, 3500),
(17181, 1, '⛺ 캠핑용 펫 전용 야외 침대', '', '💎 지면의 냉기를 차단하는 캠핑 베드\n✨ 가볍고 접이식이라 휴대성 최고\n💸 캠핑 시즌 한정 25% 할인\n▶ 침대 구경하기', '', 1990000.00, 9950),
(17182, 1, '🍼 펫 전용 락토프리 산양유', '', '🎯 소화가 잘 되어 배앓이 걱정 뚝!\n✨ 면역력 향상에 좋은 프리미엄 우유\n📌 냉장고 상비 간식으로 추천\n▶ 산양유 주문하기', '', 1380000.00, 6900),
(17183, 1, '🎈 펫 생일 파티 커스텀 케이크', '', '✨ 아이 얼굴이 들어간 수제 케이크\n💎 쌀가루와 고기로 만든 건강 간식\n📌 예약 시 파티 토퍼 무료 제작\n▶ 케이크 예약하기', '', 770000.00, 3850),
(17184, 1, '🧊 펫 쿨링 조끼 아이스 팩', '', '🔥 여름철 열사병 산책 방지 필수\n🎯 물만 묻혀도 지속되는 시원함\n💰 한정 수량 특가 세일 9,900원\n▶ 쿨조끼 확인', '', 160000.00, 800),
(17185, 1, '🧥 고어텍스 강아지 우비 신상', '', '✨ 장마철에도 쾌적한 산책 보장\n📌 모자 탈부착 가능 + 야광 띠 부착\n🚀 오늘 사면 내일 바로 입힘\n▶ 우비 구매하기', '', 1450000.00, 7250),
(17186, 1, '🏥 슬개골 보호대 좌우 세트', '', '🎯 다리 떨림이나 절뚝임 예방\n✨ 맞춤형 조절 끈으로 흘러내림 방지\n📞 구매 전 사이즈 상담 가능\n▶ 보호대 보기', '', 840000.00, 4200),
(17187, 1, '🧹 펫 털 제거 청소기 헤드', '', '💎 기존 청소기에 끼워만 주세요\n✨ 카펫과 소파의 털을 완벽 흡입\n💸 기간 한정 15,000원 단독 할인\n▶ 헤드 구매하기', '', 230000.00, 1150),
(17188, 1, '🥩 펫 수제 피자 영양 간식', '', '🎯 홈파티 주인공은 바로 우리 아이\n✨ 치즈와 닭가슴살의 환상 조합\n📌 신선 배송으로 안심하고 급여\n▶ 피자 주문하기', '', 1520000.00, 7600),
(17189, 1, '🪞 펫 아로마 테라피 자격증', '', '✨ 아이들의 심신 안정을 직접 관리\n💎 천연 오일 배합법 및 마사지 교육\n📌 수강 시 아로마 키트 무료 제공\n▶ 클래스 등록', '', 910000.00, 4550),
(17190, 1, '🧸 노즈워크 코방석 대형', '', '🎯 스트레스 풀고 두뇌 회전까지!\n✨ 다양한 간식 숨김 포켓 구성\n💰 지금 구매 시 간식 샘플 증정\n▶ 장난감 확인', '', 300000.00, 1500),
(17191, 1, '📦 유기동물 후원 팔찌 & 목걸이', '', '✨ 착한 소비로 아이들을 도와주세요\n💎 판매 수익금의 50%가 기부됩니다\n📌 리미티드 에디션 디자인 출시\n▶ 후원 동참하기', '', 1590000.00, 7950),
(17192, 1, '🛁 펫 전용 버블 입욕제 10알', '', '🎯 목욕 거부 극복! 즐거운 거품 놀이\n✨ 보습 성분 함유로 털이 보들보들\n🚀 오늘 주문 시 내일 도착 보장\n▶ 입욕제 보기', '', 980000.00, 4900),
(17193, 1, '👃 펫 전용 탈취제 숲속 향기', '', '💎 오줌 냄새를 근본적으로 분해\n✨ 유해 성분 없는 안전한 스프레이\n📌 500ml 본품 + 리필 기획팩\n▶ 탈취제 확인하기', '', 370000.00, 1850),
(17194, 1, '👔 펫 전용 체크무늬 원피스', '', '✨ 귀여움 폭발! 데이트룩의 정석\n📌 부드러운 코튼 소재로 편안함\n💰 시즌 오프 30% 즉시 할인\n▶ 원피스 보러가기', '', 1660000.00, 8300),
(17195, 1, '🚿 스마트 자동 식수대 필터', '', '🎯 24시간 깨끗하게 걸러진 물 공급\n✨ 소음이 없어 밤에도 조용해요\n💸 선착순 필터 6개월분 증정\n▶ 식수대 구매', '', 1050000.00, 5250),
(17196, 1, '🚪 방문 설치 펫 안전 펜스', '', '✨ 주방이나 현관 출입 완벽 차단\n📌 이중 잠금 장치로 더 안전하게\n📞 수도권 무료 방문 설치 이벤트\n▶ 펜스 보기', '', 440000.00, 2200),
(17197, 1, '🧶 고양이 캣닢 쿠션 생선 모양', '', '💎 냥이들이 안고 자는 애착 인형\n✨ 고함량 캣닢으로 기분 전환 최고\n📌 1+1 이벤트 놓치지 마세요\n▶ 인형 사러가기', '', 1730000.00, 8650),
(17198, 1, '🏥 펫 전용 붕대 & 소독 세트', '', '🎯 발톱 부상이나 찰과상 응급 처치\n✨ 털에 달라붙지 않는 압박 붕대\n📌 구급함 필수 구비 아이템\n▶ 붕대 보러가기', '', 1120000.00, 5600),
(17199, 1, '🥫 고양이 주식 파우치 24개입', '', '🔥 영양 균형 잡힌 맛있는 한 끼\n📌 수분 함량이 높아 결석 예방 도움\n💰 박스 구매 시 개당 700원꼴 특가\n▶ 파우치 쟁여두기', '', 510000.00, 2550),
(17200, 1, '🎀 블링블링 펫 티아라 왕관', '', '✨ 견생샷/묘생샷을 위한 필살기\n💎 가벼운 무게와 안전한 끈 고정\n📌 생일 파티 필수 액세서리\n▶ 티아라 만들기', '', 1800000.00, 9000);
