INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(17201, 1, '🐈 찰떡궁합 두부모래 7L x 4봉', '', '✨ 먼지 날림 최소화! 변기에 바로 버리세요\n💎 천연 콩앙금으로 만들어 안전합니다\n📌 쟁여두기 특가 세일 진행 중\n▶ 지금 구매하기', '', 1190000.00, 5950),
(17202, 1, '🐕 빛나는 야간 산책 LED 목줄', '', '🔥 어두운 밤길, 우리 아이 위치 확인 필수\n🎯 USB 충전 방식으로 간편하게 사용\n⚡ 오늘만 1+1 특별 이벤트 중!\n▶ 야간 산책 준비', '', 580000.00, 2900),
(17203, 1, '🥩 저염 황태채 기력 회복 보양식', '', '💎 염분기를 쏙 뺀 건강한 원물 간식\n✨ 수술 후나 환절기 보양으로 최고\n📌 무방부제/무색소 안심 공정\n▶ 보양식 주문하기', '', 1870000.00, 9350),
(17204, 1, '🏠 펫 전용 원목 식탁 2구 세트', '', '✨ 아이들 목 건강을 생각한 각도 조절\n📌 견고한 소나무 원목과 세라믹 식기\n💸 신규 가입 시 5,000원 즉시 할인\n▶ 식탁 구경하기', '', 1260000.00, 6300),
(17205, 1, '✂️ 셀프 미용 전문가용 바리깡', '', '🎯 저소음 저진동 설계로 겁 많은 아이도 OK\n💎 세밀한 길이 조절로 완성도 높은 미용\n🚀 내일 바로 배송 보장\n▶ 미용기 확인하기', '', 650000.00, 3250),
(17206, 1, '🏥 노령견 전용 눈 영양제 루테인', '', '✨ 뿌연 눈동자, 미리 관리해주세요\n📌 안구 건조 및 백내장 예방 도움\n📞 수의사가 직접 배합한 프리미엄 라인\n▶ 영양제 사러가기', '', 1940000.00, 9700),
(17207, 1, '🦴 튼튼한 면 로프 터그 장난감', '', '🔥 물고 뜯으며 스트레스 해소 팍팍\n🎯 치석 제거 효과까지 챙기는 똑똑한 놀이\n💰 3개 세트 구매 시 30% 할인\n▶ 바로 구매하기', '', 1330000.00, 6650),
(17208, 1, '✈️ 반려동물 동반 캠핑장 리스트', '', '🐕 이번 주말은 아이와 함께 캠핑 어때요?\n✨ 운동장 완비된 전국 펫 캠핑장 정보\n📌 지금 예약 시 캠핑용 간식 키트 증정\n▶ 캠핑장 예약하기', '', 720000.00, 3600),
(17209, 1, '🧼 펫 전용 약용 샴푸 피부염 개선', '', '💎 곰팡이성 피부염, 가려움증 완화\n✨ 수의사 처방 성분으로 안심 케어\n🎯 첫 구매 시 전용 브러쉬 증정\n▶ 제품 확인하기', '', 110000.00, 550),
(17210, 1, '🎡 캣타워 전용 해먹 추가 키트', '', '🔥 냥이들이 가장 좋아하는 꿀잠 명당\n📌 기존 캣타워에 간편 설치 가능\n💰 한정 수량 단독 20% 세일\n▶ 해먹 구매하기', '', 1400000.00, 7000),
(17211, 1, '📺 펫 전용 자동 공 던지기 기기', '', '✨ 지치지 않는 에너지, 기계가 놀아줘요\n📌 비거리 조절 가능 + 실내외 겸용\n🎯 분리불안 완화에 효과 만점\n▶ 제품 보기', '', 790000.00, 3950),
(17212, 1, '🧶 마따따비 막대 냥이 환장템', '', '💎 스트레스 해소와 치아 관리의 끝판왕\n✨ 100% 천연 소재로 안심하고 씹어요\n🚀 오늘 주문 시 사은품 증정\n▶ 냥이 장난감 사기', '', 180000.00, 900),
(17213, 1, '🥤 휴대용 펫 전용 급수 식기', '', '🎯 산책 중에도 깨끗한 물을 마셔요\n📌 접이식 디자인으로 휴대성 극대화\n💸 단독 특가 7,900원 한정 수량\n▶ 식기 확인하기', '', 1470000.00, 7350),
(17214, 1, '📸 우리 아이 굿즈 제작 커스텀', '', '✨ 사진만 보내주면 키링/폰케이스 완성\n💎 세상에 하나뿐인 나만의 아이템\n📌 대량 주문 시 추가 할인 혜택\n▶ 굿즈 만들기', '', 860000.00, 4300),
(17215, 1, '📚 반려동물 응급처치 가이드북', '', '🎯 위급 상황, 당황하지 말고 따라 하세요\n✨ 초보 집사 필수 상식 100가지\n💰 도서 구매 시 구급함 세트 할인\n▶ 도서 자세히 보기', '', 250000.00, 1250),
(17216, 1, '🦷 바르는 치약 칫솔 없이 간편', '', '🔥 양치가 힘든 아이를 위한 최고의 대안\n📌 잇몸 질환 및 구취 제거에 탁월\n⚡ 2개 구매 시 1개 추가 증정\n▶ 치약 구매하기', '', 1540000.00, 7700),
(17217, 1, '🧺 펫 전용 극세사 담요 포근함', '', '✨ 구름 같은 부드러움으로 꿀잠 예약\n💎 털이 잘 안 붙는 특수 가공 원단\n📌 겨울 산책 외출 시 필수템\n▶ 담요 보러가기', '', 930000.00, 4650),
(17218, 1, '🍗 동결건조 연어 트릿 대용량', '', '🎯 영양 손실 제로! 바삭한 식감\n✨ 고단백 저칼로리 최고의 훈련 간식\n💰 박스 기획팩 역대급 할인 중\n▶ 쟁여두기 클릭', '', 320000.00, 1600),
(17219, 1, '🧥 강아지 프릴 원피스 봄 신상', '', '💎 꽃보다 예쁜 우리 아이 코디 완성\n✨ 신축성 좋은 소재로 편안함까지\n📌 무신사 펫 단독 입점 세일\n▶ 신상 구경하기', '', 1610000.00, 8050),
(17220, 1, '🏃‍♂️ 펫 전용 짐볼 코어 강화 운동', '', '🔥 집에서 즐기는 전문 재활 트레이닝\n🎯 관절 수술 후 근육 유지에 필수\n💸 지금 구매 시 1:1 코칭권 증정\n▶ 피트니스 보기', '', 1000000.00, 5000),
(17221, 1, '🧴 펫 발바닥 보습 크림 유기농', '', '✨ 거칠어진 발바닥을 아기 피부처럼\n💎 끈적임 없이 빠르게 흡수됩니다\n📌 산책 후 필수 관리 아이템\n▶ 크림 구매하기', '', 390000.00, 1950),
(17222, 1, '🥣 자동 회전식 급식기 6구형', '', '📌 시간마다 열리는 신선한 식사\n✨ 습식 사료 보관도 가능한 쿨링 기능\n💸 기간 한정 15% 즉시 할인\n▶ 급식기 보러가기', '', 1680000.00, 8400),
(17223, 1, '🎒 펫 슬링백 포대기형 이동장', '', '🎯 주인의 품처럼 아늑한 밀착형 디자인\n✨ 가벼운 외출이나 쇼핑 갈 때 딱!\n🚀 오늘 주문 시 내일 도착 보장\n▶ 슬링백 쇼핑', '', 1070000.00, 5350),
(17224, 1, '🥬 펫 전용 야채 칩 건강 간식', '', '💎 고구마, 단호박의 달콤함 그대로\n✨ 비만 걱정 없는 저칼로리 간식\n📌 낱개 포장으로 간편한 휴대\n▶ 야채칩 사러가기', '', 460000.00, 2300),
(17225, 1, '🧬 반려동물 MBTI 성향 테스트', '', '🎯 우리 아이의 진짜 속마음은?\n✨ 전문가의 설문을 통한 성격 분석\n📞 행동 교정 팁 리포트 무료 제공\n▶ 테스트 신청하기', '', 1750000.00, 8750),
