(17272, 1, '🥣 세라믹 펫 식기 높이 조절식', '', '📌 아이들의 목 관절을 생각한 설계\n✨ 성장 단계에 맞춰 높이 조절 가능\n💸 오픈 기념 30% 선착순 할인\n▶ 식기 보러가기', '', 1580000.00, 7900),
(17273, 1, '🎒 펫 이동장 백팩 확장형', '', '🎯 여행 갈 때 필수! 넓은 수납 공간\n✨ 등판 매쉬 소재로 쾌적한 착용감\n🚀 오늘 주문 시 내일 바로 출발\n▶ 이동장 쇼핑', '', 970000.00, 4850),
(17274, 1, '🥬 펫 전용 과일 혼합 칩 세트', '', '💎 사과, 바나나, 딸기 영양 그대로\n✨ 비타민 가득한 천연 원물 간식\n📌 다이어트가 필요한 아이 추천\n▶ 과일칩 사러가기', '', 360000.00, 1800),
(17275, 1, '🧬 펫 알러지 검사 서비스 키트', '', '🎯 가려움증의 원인을 집에서 찾으세요\n✨ 120가지 주요 항목 정밀 분석\n📞 검사 결과 모바일 리포트 제공\n▶ 검사 신청하기', '', 1650000.00, 8250),
(17276, 1, '🪑 거실용 펫 계단 논슬립 스텝', '', '✨ 높은 침대도 안전하게 오르내려요\n📌 미끄럼 방지 패드 + 푹신한 쿠션\n💰 오늘만 특가 19,900원 한정\n▶ 펫계단 보기', '', 1040000.00, 5200),
(17277, 1, '🚑 야간 응급 동물병원 찾기 앱', '', '🎯 새벽에도 당황하지 말고 클릭!\n✨ 현재 진료 가능한 병원 실시간 매칭\n📌 앱 결제 시 진료비 추가 할인\n▶ 앱 설치하기', '', 430000.00, 2150),
(17278, 1, '🐟 연어 껍질 껌 피모 개선 전용', '', '💎 콜라겐 가득! 윤기 나는 털 관리\n✨ 알러지 걱정 없는 생선 단백질\n💸 3팩 구매 시 1팩 추가 증정\n▶ 껌 구매하기', '', 1720000.00, 8600),
(17279, 1, '🧣 집사랑 커플 후드티 펫 세트', '', '✨ 산책길 시선 강탈! 커플 룩 완성\n📌 기모 안감으로 겨울에도 포근하게\n💰 세트 구매 시 사은품 증정\n▶ 커플템 보러가기', '', 1110000.00, 5550),
(17280, 1, '🧼 펫 발바닥 보호 왁스 스틱', '', '🎯 거친 땅으로부터 발바닥 보호\n✨ 천연 성분으로 먹어도 안심하세요\n📌 산책 전후 슥슥 발라주면 끝\n▶ 보호 왁스 쇼핑', '', 500000.00, 2500),
(17281, 1, '⛺ 캠핑용 펫 전용 야외 침대', '', '💎 지면의 냉기와 수분 차단!\n✨ 가볍고 접이식이라 휴대성 최고\n💸 캠핑 시즌 한정 25% 특가\n▶ 침대 구경하기', '', 1790000.00, 8950),
(17282, 1, '🍼 펫 전용 락토프리 산양유', '', '🎯 소화 잘 되는 프리미엄 영양 간식\n✨ 면역력 향상에 도움을 줍니다\n📌 냉장 보관 시 신선도 유지\n▶ 산양유 주문하기', '', 1180000.00, 5900),
(17283, 1, '🎈 펫 생일 파티 커스텀 케이크', '', '✨ 아이 얼굴이 들어간 수제 케이크\n💎 쌀가루와 육류로 만든 건강식\n📌 예약 시 파티 토퍼 무료 제작\n▶ 케이크 예약하기', '', 570000.00, 2850),
(17284, 1, '🧊 펫 쿨 조끼 아이스 팩 삽입', '', '🔥 여름철 열사병 산책 방지 필수템\n🎯 물만 적셔도 시원함이 지속됩니다\n💰 한정 수량 특가 세일 9,900원\n▶ 쿨조끼 확인', '', 1860000.00, 9300),
(17285, 1, '🧥 고어텍스 강아지 우비 신상', '', '✨ 비 오는 날 산책도 두렵지 않다\n📌 모자 탈부착 및 야광 띠 부착\n🚀 오늘 사면 내일 바로 사용 가능\n▶ 우비 구매하기', '', 1250000.00, 6250),
(17286, 1, '🏥 슬개골 보호대 전문 브랜드', '', '🎯 다리 떨림이나 탈구 방지 및 보호\n✨ 맞춤형 설계로 활동성 보장\n📞 구매 전 전문가 사이즈 상담\n▶ 보호대 보기', '', 640000.00, 3200),
(17287, 1, '🧹 펫 털 제거 청소기용 노즐', '', '💎 침구와 소파의 털을 완벽 흡입\n✨ 반려동물 가정 필수 가전 액세서리\n💸 기간 한정 10,000원 단독 할인\n▶ 노즐 구매하기', '', 1930000.00, 9650),
(17288, 1, '🥩 펫 수제 피자 영양 특식', '', '🎯 홈파티 주인공은 바로 우리 아이\n✨ 고구마 도우와 고기 토핑의 조화\n📌 신선 배송으로 안심하고 급여\n▶ 피자 주문하기', '', 1320000.00, 6600),
(17289, 1, '🪞 펫 아로마 테라피 원데이 클래스', '', '✨ 아이들의 스트레스를 향기로 케어\n💎 천연 오일 제작 및 마사지 실습\n📌 수강 시 아로마 샘플 키트 증정\n▶ 클래스 등록', '', 710000.00, 3550),
(17290, 1, '🧸 노즈워크 코방석 10구 대형', '', '🎯 지능 발달과 스트레스 해소를 동시에\n✨ 다양한 간식 포켓으로 난이도 조절\n💰 지금 구매 시 간식 샘플 증정\n▶ 장난감 확인', '', 100000.00, 500),
(17291, 1, '📦 유기동물 후원 팔찌 & 목걸이', '', '✨ 당신의 구매가 아이들의 사료가 됩니다\n💎 판매 수익금의 50%가 정기 기부\n📌 리미티드 에디션 굿즈 출시\n▶ 후원 동참하기', '', 1390000.00, 6950),
(17292, 1, '🛁 펫 전용 거품 입욕제 세트', '', '🎯 목욕 시간을 즐거운 놀이 시간으로\n✨ 보습 성분 함유로 모질 개선 효과\n🚀 오늘 주문 시 내일 도착 보장\n▶ 입욕제 보기', '', 780000.00, 3900),
(17293, 1, '👃 펫 전용 강력 탈취제 세트', '', '💎 오줌 냄새와 체취를 근본적으로 제거\n✨ 유해 화학 성분 없는 안전한 선택\n📌 500ml 본품 + 리필 기획팩\n▶ 탈취제 확인하기', '', 170000.00, 850),
(17294, 1, '👔 펫 전용 체크무늬 원피스', '', '✨ 사랑스러운 공주님 변신 완료!\n📌 부드러운 코튼 소재로 편안함 보장\n💰 시즌 오프 30% 파격 세일 중\n▶ 원피스 보러가기', '', 1460000.00, 7300),
(17295, 1, '🚿 스마트 자동 정수기 필터 증정', '', '🎯 24시간 흐르는 깨끗한 물 공급\n✨ 저소음 설계로 밤에도 조용해요\n💸 선착순 필터 6개월분 추가 증정\n▶ 정수기 구매', '', 850000.00, 4250),
(17296, 1, '🚪 방문 설치 펫 안전 펜스', '', '✨ 주방이나 현관 출입 완벽 차단\n📌 이중 잠금 시스템으로 보안 강화\n📞 수도권 무료 방문 실측 서비스\n▶ 펜스 보기', '', 240000.00, 1200),
(17297, 1, '🧶 고양이 캣닢 인형 생선 세트', '', '💎 냥이들이 물고 빨아도 튼튼한 원단\n✨ 고함량 국산 캣닢 사용 완료\n📌 1+1 이벤트로 두 마리도 거뜬\n▶ 인형 사러가기', '', 1530000.00, 7650),
(17298, 1, '🏥 펫 구급상자 가정 비치용', '', '🎯 비상시 당황하지 말고 챙기세요\n✨ 붕대, 소독약, 핀셋 풀세트 구성\n📌 응급처치 가이드북 무료 포함\n▶ 구급함 보러가기', '', 920000.00, 4600),
(17299, 1, '🥫 고양이 주식 파우치 대용량팩', '', '🔥 영양 균형 잡힌 맛있는 습식 한 끼\n📌 수분 함량이 높아 신장 건강에 도움\n💰 박스 구매 시 개당 최저가 도전\n▶ 파우치 쟁여두기', '', 310000.00, 1550),
(17300, 1, '🎀 블링블링 펫 티아라 머리띠', '', '✨ 견생샷/묘생샷 촬영 필수 소품\n💎 가벼운 무게와 편안한 끈 조절\n📌 생일 파티 및 특별한 날 추천\n▶ 티아라 만들기', '', 1600000.00, 8000);
