INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(17301, 1, '🐈 두부모래 극세입자 7L', '', '✨ 벤토나이트의 촉감과 두부의 깔끔함을 동시에!\n💎 먼지 없는 사막화 방지 솔루션\n📌 6봉 묶음 구매 시 무료 배송\n▶ 모래 쇼핑하기', '', 990000.00, 4950),
(17302, 1, '🐕 튼튼한 리드줄 가슴줄 세트', '', '🔥 당김 방지 설계로 편안한 산책 환경\n🎯 고강도 나일론 소재로 끊어질 걱정 NO\n⚡ 신규 컬러 5종 출시 기념 할인\n▶ 산책 용품 보기', '', 380000.00, 1900),
(17303, 1, '🥩 저알러지 오리 안심 육포', '', '💎 피부가 예민한 아이를 위한 선택\n✨ 인공 첨가물 없는 100% 원물 수제 간식\n📌 대용량 기획팩으로 가성비 업\n▶ 간식 주문하기', '', 1670000.00, 8350),
(17304, 1, '🏠 원목 펫 스텝 3단 계단', '', '✨ 소파와 침대를 안전하게 오르내려요\n📌 흔들림 없는 묵직한 자작나무 원목\n💸 한정 수량 20% 단독 세일\n▶ 펫스텝 구경하기', '', 1060000.00, 5300),
(17305, 1, '✂️ 저소음 부분 미용 발바닥 이발기', '', '🎯 발가락 사이 털도 정밀하게 컷팅\n💎 USB 충전식으로 언제 어디서나 간편\n🚀 오늘 사면 내일 바로 도착\n▶ 미용기 구매', '', 450000.00, 2250),
(17306, 1, '🏥 강아지 유산균 60일분 세트', '', '✨ 원활한 배변 활동과 면역력 강화\n📌 100억 CFU 보장 프리미엄 균주\n📞 수의사가 성분 배합한 안심 포뮬러\n▶ 유산균 보러가기', '', 1740000.00, 8700),
(17307, 1, '🦴 천연 고무 치어링 링 장난감', '', '🔥 씹을수록 치석이 제거되는 마법\n🎯 분리불안 해소에 도움을 주는 아이템\n💰 2개 구매 시 10% 추가 할인\n▶ 장난감 쇼핑', '', 1130000.00, 5650),
(17308, 1, '✈️ 펫 프렌들리 글램핑 패키지', '', '🐕 댕댕이랑 불멍하며 힐링하는 주말\n✨ 전용 운동장과 펫 어메니티 완비\n📌 선착순 예약 시 수제 간식 제공\n▶ 여행 예약하기', '', 520000.00, 2600),
(17309, 1, '🧼 펫 드라이 샴푸 물 없는 목욕', '', '💎 산책 후 발만 닦을 때 정말 편해요\n✨ 자연 유래 성분 거품으로 자극 제로\n🎯 휴대용 사이즈 증정 이벤트 중\n▶ 제품 확인하기', '', 1810000.00, 9050),
(17310, 1, '🎡 캣타워 전용 스크래처 리필', '', '🔥 닳아버린 기둥, 새것처럼 교체하세요\n📌 고밀도 골판지로 가루 날림 최소화\n💰 전 모델 호환 가능 특가 상품\n▶ 리필 구매하기', '', 1200000.00, 6000),
(17311, 1, '📺 스마트 펫 급수기 UV 살균', '', '✨ 물때 걱정 없는 자동 살균 시스템\n📌 2.5L 대용량으로 장기 외출도 안심\n🎯 필터 1년치 포함 패키지 한정판\n▶ 급수기 보기', '', 590000.00, 2950),
(17312, 1, '🧶 고양이 캣닢 캔디 벽부착형', '', '💎 냥이들의 스트레스를 한 번에 날려요\n✨ 회전형 디자인으로 흥미 유발 만점\n🚀 로켓 배송으로 빠르게 굴려주세요\n▶ 캔디 사러가기', '', 1880000.00, 9400),
(17313, 1, '🥤 펫 전용 이온 음료 200ml', '', '🎯 격한 놀이 후 빠른 수분 보충\n📌 전해질 균형으로 활력 충전 완료\n💸 10개입 박스 구매 시 25% 할인\n▶ 워터 확인하기', '', 1270000.00, 6350),
