(17358, 1, '✈️ 반려동물 전용 카시트 대형', '', '🐕 차 안에서도 편안하고 안전하게\n✨ 충격 흡수 쿠션과 안전벨트 연결고리\n📌 캠핑 갈 때 필수 아이템\n▶ 카시트 예약하기', '', 420000.00, 2100),
(17359, 1, '🧼 펫 전용 저자극 샴푸 바', '', '💎 플라스틱 없는 친환경 목욕 시간\n✨ 천연 오일로 보습 효과 극대화\n🎯 샴푸 바 구매 시 전용 거품망 증정\n▶ 제품 확인하기', '', 1710000.00, 8550),
(17360, 1, '🎡 벽 부착형 고양이 캣워크', '', '🔥 공간 활용 끝판왕! 수직 공간 창조\n📌 튼튼한 하중 지지 설계 완료\n💰 한정 수량 단독 35% 할인 중\n▶ 캣워크 쇼핑하기', '', 1100000.00, 5500),
(17361, 1, '📺 스마트 펫 모니터링 로봇', '', '✨ 스스로 움직이며 아이와 놀아줘요\n📌 실시간 영상 확인 및 간식 투척 기능\n🎯 얼리버드 특가 한정 수량 판매\n▶ 로봇 보기', '', 490000.00, 2450),
(17362, 1, '🧶 고양이 깃털 낚싯대 10종 세트', '', '💎 다양한 모양으로 질릴 틈 없는 사냥\n✨ 튼튼한 탄성 와이어 적용\n🚀 오늘 사면 내일 바로 사냥 시작\n▶ 장난감 구매', '', 1780000.00, 8900),
(17363, 1, '🥤 펫 전용 워터 보틀 휴대용', '', '🎯 산책 중 원터치 급수 시스템\n📌 남은 물은 다시 넣는 절약 기능\n💸 기간 한정 1+1 특별 이벤트\n▶ 급수기 확인하기', '', 1170000.00, 5850),
(17364, 1, '📸 펫 야외 프로필 촬영 패키지', '', '✨ 자연광 아래서 가장 예쁜 모습 기록\n💎 원본 데이터 전체 제공 서비스\n📌 예약 시 인화 사진 5장 무료\n▶ 촬영 예약하기', '', 560000.00, 2800),
(17365, 1, '📚 반려동물 영양학 기초 가이드', '', '🎯 내 아이에게 맞는 사료 고르는 법\n✨ 성분 분석표 완벽 해부 전략\n💰 도서 구매 시 영양 간식 증정\n▶ 도서 자세히 보기', '', 1850000.00, 9250),
(17366, 1, '🦷 펫 전용 덴탈 워터 음수형', '', '🔥 물에 타주기만 하면 구강 관리 끝\n📌 치태 형성 억제 및 구취 완화\n⚡ 단 7일간 20% 할인 이벤트\n▶ 덴탈 워터 구매', '', 1240000.00, 6200),
(17367, 1, '🧺 펫 전용 텐셀 쿨매트 시트', '', '✨ 무더운 여름, 닿자마자 시원하게\n💎 쿨링 원단으로 체온 상승 방지\n📌 노령견/노령묘 여름 필수템\n▶ 쿨매트 보기', '', 630000.00, 3150),
(17368, 1, '🍗 동결건조 양고기 트릿 70g', '', '🎯 저알러지 고단백 보양 간식\n✨ 원물 본연의 맛과 향이 가득\n💰 2개 사면 1개 더! 2+1 행사\n▶ 혜택받기 클릭', '', 1920000.00, 9600),
(17369, 1, '🧥 강아지 데님 자켓 레트로 신상', '', '💎 산책길 패셔니스타 등극 아이템\n✨ 부드러운 데님 소재로 편안함까지\n📌 무신사 펫 단독 런칭 특가\n▶ 자켓 구경하기', '', 1310000.00, 6550),
(17370, 1, '🏃‍♂️ 펫 피트니스 균형 보드 운동', '', '🔥 뒷다리 힘을 길러주는 밸런스 운동\n🎯 슬개골 탈구 예방 및 재활 도움\n💸 지금 구매 시 코칭권 증정\n▶ 피트니스 보기', '', 700000.00, 3500),
(17371, 1, '🧴 펫 발바닥 보습 에센스 롤온', '', '✨ 건조한 발바닥에 영양 공급\n💎 롤온 타입으로 손에 안 묻어 간편\n📌 산책 후 데일리 케어 추천\n▶ 에센스 구매', '', 1990000.00, 9950),
(17372, 1, '🥣 펫 자동 식기 세트 2구형', '', '📌 정해진 시간에 신선한 사료 급여\n✨ 스테인리스 볼로 위생적인 관리\n💸 오픈 기념 25% 선착순 할인\n▶ 식기 보러가기', '', 1380000.00, 6900),
(17373, 1, '🎒 펫 이동장 캐리어 백팩 휠형', '', '🎯 무거운 아이도 바퀴로 편하게 이동\n✨ 기내 반입 가능한 사이즈 구성\n🚀 오늘 주문 시 내일 바로 출발\n▶ 이동장 쇼핑', '', 770000.00, 3850),
(17374, 1, '🥬 펫 전용 야채 건조 간식 세트', '', '💎 당근, 브로콜리, 단호박의 건강함\n✨ 칭찬용 작은 사이즈로 딱 좋아요\n📌 다이어트 식단 관리 필수템\n▶ 간식 사러가기', '', 160000.00, 800),
(17375, 1, '🧬 펫 건강 진단 키트 소변용', '', '🎯 집에서 확인하는 10가지 건강 지표\n✨ 이상 징후 조기 발견의 시작\n📞 결과 분석 서비스 무료 제공\n▶ 키트 신청하기', '', 1450000.00, 7250),
(17376, 1, '🪑 거실용 펫 계단 가죽 스텝', '', '✨ 오염에 강하고 관리가 쉬운 소재\n📌 탄탄한 고밀도 스펀지로 하중 지지\n💰 오늘만 특가 29,900원 한정\n▶ 펫계단 보기', '', 840000.00, 4200),
(17377, 1, '🚑 근처 애견 미용실 예약 앱', '', '🎯 우리 동네 미용실 가격 비교 예약\n✨ 포트폴리오 보고 스타일 선택\n📌 첫 방문 미용 시 펫 샴푸 증정\n▶ 앱 설치하기', '', 230000.00, 1150),
(17378, 1, '🐟 고양이 전용 연어 큐브 간식', '', '💎 오메가3 가득! 피모 건강에 최고\n✨ 한 입 크기로 먹기 좋은 사이즈\n💸 3팩 구매 시 1팩 추가 증정\n▶ 간식 구매하기', '', 1520000.00, 7600),
(17379, 1, '🧣 집사랑 커플 수면 잠옷 세트', '', '✨ 집에서도 함께하는 포근한 커플 룩\n📌 부드러운 극세사 원단으로 꿀잠\n💰 세트 구매 시 전용 양말 증정\n▶ 커플템 보러가기', '', 910000.00, 4550),
(17380, 1, '🧼 펫 발바닥 클리너 폼 타입', '', '🎯 물 없이 사용하는 간편 세정 거품\n✨ 실리콘 브러쉬 일체형으로 편리함\n📌 산책 필수 준비물 1위\n▶ 클리너 쇼핑', '', 300000.00, 1500),
(17381, 1, '⛺ 캠핑용 펫 전용 야외 쿨텐트', '', '💎 통풍이 잘되는 매쉬 소재 텐트\n✨ 해충 방지 코팅 원단 사용 완료\n💸 캠핑 시즌 맞이 25% 할인\n▶ 텐트 구경하기', '', 1590000.00, 7950),
(17382, 1, '🍼 펫 전용 유기농 염소 우유', '', '🎯 소화가 빠른 고품격 영양 공급원\n✨ 멸균 처리로 실온 보관 가능\n📌 팩당 1,500원꼴 파격 박스 세일\n▶ 우유 주문하기', '', 980000.00, 4900),
(17383, 1, '🎈 펫 파티 소품 랜덤 박스', '', '✨ 고깔, 케이크 토퍼, 풍선 풀세트\n💎 무엇이 나올지 기대되는 즐거움\n📌 가격 대비 2배 이상의 구성\n▶ 박스 확인하기', '', 370000.00, 1850),
(17384, 1, '🧊 펫 쿨링 넥카라 냉감 소재', '', '🔥 목 주변 온도를 낮춰 시원하게\n🎯 여름 산책 시 체온 조절 필수품\n💰 최저가 도전 7,900원 한정\n▶ 넥카라 확인', '', 1660000.00, 8300),
(17385, 1, '🧥 강아지 올인원 바람막이 신상', '', '✨ 환절기 먼지 차단과 체온 유지\n📌 생활 방수 기능으로 가벼운 비 가능\n🚀 오늘 주문 시 내일 도착 보장\n▶ 바람막이 구매', '', 1050000.00, 5250),
(17386, 1, '🏥 슬개골 보호용 강아지 신발', '', '🎯 미끄러운 바닥에서도 안정적으로\n✨ 발목 지지력이 우수한 특수 설계\n📞 구매 전 사이즈 측정법 상담\n▶ 신발 보기', '', 440000.00, 2200),
(17387, 1, '🧹 펫 털 제거 돌돌이 리필 세트', '', '💎 강력한 점착력으로 미세 털까지\n✨ 의류 및 침구 관리의 혁명\n💸 대용량 12롤 기획 구성 특가\n▶ 리필 구매하기', '', 1730000.00, 8650),
(17388, 1, '🥩 펫 전용 스테이크 특식 박스', '', '🎯 특별한 날을 위한 한우 스테이크\n✨ 가니쉬와 소스까지 완벽한 구성\n📌 냉동 배송으로 신선함 유지\n▶ 스테이크 주문', '', 1120000.00, 5600),
(17389, 1, '🪞 펫 매니저 실무 온라인 교육', '', '✨ 펫 비즈니스 창업의 모든 것\n💎 고객 관리 및 마케팅 전략 전수\n📌 수강생 전용 비즈니스 팩 증정\n▶ 클래스 등록', '', 510000.00, 2550),
(17390, 1, '🧸 노즈워크 숨바꼭질 인형 세트', '', '🎯 인형 속에 인형이? 호기심 자극\n✨ 삑삑이 소리로 흥미 유발 만점\n💰 지금 구매 시 간식 샘플 증정\n▶ 장난감 확인', '', 1800000.00, 9000),
(17391, 1, '📦 유기견 돕기 자선 캘린더', '', '✨ 1년 내내 아이들과 함께하는 기부\n💎 예쁜 일러스트와 펫 상식 수록\n📌 수익금 전액 사료 기부 사용\n▶ 캘린더 구매', '', 1190000.00, 5950),
(17392, 1, '🛁 펫 전용 아로마 입욕제 5종', '', '🎯 향기로운 목욕 시간의 완성\n✨ 민감성 피부용 무향 옵션 선택 가능\n🚀 오늘 주문 시 사은품 증정\n▶ 입욕제 보기', '', 580000.00, 2900),
(17393, 1, '👃 펫 전용 탈취제 편백나무 향', '', '💎 자연의 향기로 냄새와 세균 제거\n✨ 피톤치드 성분으로 공기 정화\n📌 1+1 이벤트 진행 중(수량 한정)\n▶ 탈취제 확인하기', '', 1870000.00, 9350),
(17394, 1, '👔 펫 전용 세일러 셔츠 & 모자', '', '✨ 마린 룩으로 연출하는 귀여운 코디\n📌 여름 휴가지에서 인생샷 보장\n💰 신상 출시 기념 20% 할인\n▶ 코디 보러가기', '', 1260000.00, 6300),
(17395, 1, '🚿 스마트 자동 정수기 필터 팩', '', '🎯 매일매일 깨끗한 물을 마셔요\n✨ 미세 불순물을 걸러주는 여과 필터\n💸 정기 구독 시 추가 할인 혜택\n▶ 필터 구매하기', '', 650000.00, 3250),
(17396, 1, '🚪 펫 전용 계단식 안전 펜스', '', '✨ 높이 조절이 가능한 가변형 펜스\n📌 튼튼한 철제 프레임으로 파손 걱정 X\n📞 전국 무료 배송 서비스 지원\n▶ 펜스 보기', '', 1940000.00, 9700),
(17397, 1, '🧶 고양이 캣닢 인형 생선 모양', '', '💎 냥이들이 좋아하는 향긋한 캣닢\n✨ 물고 뜯어도 안전한 원단 사용\n📌 1+1 혜택으로 두 마리도 거뜬\n▶ 인형 사러가기', '', 1330000.00, 6650),
(17398, 1, '🏥 펫 응급처치 구급 가방 세트', '', '🎯 산책이나 여행 시 필수 상비약\n✨ 핀셋, 붕대, 소독약 등 12종 구성\n📌 가방 포함으로 보관이 용이함\n▶ 구급함 확인', '', 720000.00, 3600),
(17399, 1, '🥫 고양이 주식 캔 영양 가득 세트', '', '🔥 수분 함량 80% 이상의 건강한 습식\n📌 결석 예방을 위한 필수 주식\n💰 박스 구매 시 개당 900원 특가\n▶ 캔 사료 쟁여두기', '', 110000.00, 550),
(17400, 1, '🎀 펫 전용 레이스 케이프 왕관', '', '✨ 공주님 변신은 한순간! 촬영 소품\n💎 가벼운 소재로 장시간 착용 가능\n📌 생일 파티 패키지 인기 상품\n▶ 케이프 보러가기', '', 1400000.00, 7000);
