INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(17401, 1, '🐈 벤토나이트 모래 대용량 20kg', '', '✨ 먼지 zero! 강력한 응고력으로 화장실 쾌적\n💎 다묘 가정 필수 가성비 끝판왕\n📌 지금 구매 시 전용 삽 증정\n▶ 모래 쟁여두기', '', 790000.00, 3950),
(17402, 1, '🐕 프리미엄 가죽 하네스 수제', '', '🔥 천연 가죽의 부드러움과 견고한 내구성\n🎯 쓸림 방지 설계로 편안한 산책\n⚡ 이니셜 각인 서비스 무료 진행 중\n▶ 하네스 보기', '', 180000.00, 900),
(17403, 1, '🥩 무항생제 닭안심 육포 200g', '', '💎 원물 그대로 말린 담백한 건강 간식\n✨ 칭찬용, 훈련용으로 활용도 최고\n📌 3봉 세트 구매 시 15% 할인\n▶ 간식 주문하기', '', 1470000.00, 7350),
(17404, 1, '🏠 펫 전용 메모리폼 마약 방석', '', '✨ 구름 위에 떠 있는 듯한 포근한 숙면\n📌 관절이 약한 아이들을 위한 저탄성 폼\n💸 첫 구매 고객 5,000원 쿠폰 발급\n▶ 방석 구경하기', '', 860000.00, 4300),
(17405, 1, '✂️ 펫 전용 안심 발톱 갈이 기기', '', '🎯 깎는 대신 갈아주세요! 출혈 걱정 제로\n💎 저소음 모터로 거부감을 줄였습니다\n🚀 오늘 사면 내일 바로 배송\n▶ 네일 그라인더 보기', '', 250000.00, 1250),
(17406, 1, '🏥 노령묘 전용 신장 보조제 츄르', '', '✨ 기호성 폭발! 먹이기 쉬운 액상 타입\n📌 신장 수치 관리와 수분 보충을 동시에\n📞 수의사가 개발에 참여한 안심 제품\n▶ 영양제 사러가기', '', 1540000.00, 7700),
(17407, 1, '🦴 펫 전용 튼튼한 라텍스 공', '', '🔥 아무리 씹어도 터지지 않는 탄성\n🎯 천연 고무 소재로 치아 건강까지\n💰 3개 묶음 9,900원 특가 진행\n▶ 공 구매하기', '', 930000.00, 4650),
(17408, 1, '✈️ 펫 동반 부산 시티 투어 패키지', '', '🐕 광안리 바다를 아이와 함께 거닐어요\n✨ 펫 전용 전세 버스와 숙소 포함\n📌 지금 예약 시 여행용 식기 세트 증정\n▶ 여행 예약하기', '', 320000.00, 1600),
(17409, 1, '🧼 펫 전용 저자극 버블 샴푸', '', '💎 펌핑 즉시 나오는 쫀쫀한 거품\n✨ 목욕 시간을 절반으로 줄여줘요\n🎯 향기 지속력 48시간 보장\n▶ 제품 확인하기', '', 1610000.00, 8050),
(17410, 1, '🎡 고양이 수직 공간 윈도우 해먹', '', '🔥 창가 햇살 아래 냥이의 꿀잠 명당\n📌 강력한 흡착력으로 15kg까지 거뜬\n💰 오늘만 30% 타임 세일\n▶ 해먹 쇼핑하기', '', 1000000.00, 5000),
(17411, 1, '📺 스마트 펫 자동 장난감 볼', '', '✨ 혼자 있는 아이를 위한 활동량 관리\n📌 장애물 회피 기능 탑재로 멈추지 않아요\n🎯 배터리 걱정 없는 USB 충전식\n▶ 제품 보기', '', 390000.00, 1950),
(17412, 1, '🧶 고양이 마따따비 나무 막대', '', '💎 양치 효과와 스트레스 해소를 한 번에\n✨ 자연에서 온 건강한 장난감\n🚀 주문 당일 발송 완료\n▶ 나무막대 구매', '', 1680000.00, 8400),
(17413, 1, '🥤 펫 전용 비타민 워터 멀티팩', '', '🎯 수분과 영양을 동시에 공급하세요\n📌 산책 후 기력 회복에 탁월\n💸 24개입 한 박스 특가 세일\n▶ 워터 주문하기', '', 1070000.00, 5350),
(17414, 1, '📸 펫 전용 포토 키링 제작 서비스', '', '✨ 우리 아이 얼굴로 만드는 세상 하나뿐인 굿즈\n💎 선명한 화질과 튼튼한 아크릴 소재\n📌 선물용으로도 인기 만점\n▶ 굿즈 제작하기', '', 460000.00, 2300),
(17415, 1, '📚 반려동물 수제 간식 레시피북', '', '🎯 집에서 만드는 건강하고 맛있는 간식\n✨ 50가지 다양한 레시피 수록\n💰 도서 구매 시 계량 스푼 증정\n▶ 도서 자세히 보기', '', 1750000.00, 8750),
(17416, 1, '🦷 펫 전용 360도 회전 칫솔', '', '🔥 어느 각도에서도 깨끗한 치아 관리\n📌 부드러운 극세모로 잇몸 자극 최소화\n⚡ 2개 세트 구매 시 20% 할인\n▶ 칫솔 구매하기', '', 1140000.00, 5700),
(17417, 1, '🧺 펫 전용 리버시블 사계절 방석', '', '✨ 여름은 시원하게, 겨울은 따뜻하게\n💎 오염에 강한 방수 코팅 원단 사용\n📌 넉넉한 사이즈로 대형견도 가능\n▶ 방석 보러가기', '', 530000.00, 2650),
(17418, 1, '🍗 동결건조 가자미 트릿 60g', '', '🎯 단백질 가득! 흰살 생선의 담백함\n✨ 알러지 걱정 없는 깨끗한 간식\n💰 3+1 증정 이벤트 진행 중\n▶ 트릿 구매하기', '', 1820000.00, 9100),
(17419, 1, '🧥 강아지 퀼팅 패딩 베스트 신상', '', '💎 가볍고 따뜻한 겨울 산책 필수템\n✨ 하네스 일체형으로 외출이 편해요\n📌 무신사 펫 인기 랭킹 상위권\n▶ 패딩 구경하기', '', 1210000.00, 6050),
(17420, 1, '🏃‍♂️ 펫 피트니스 허들 세트 실내용', '', '🔥 즐거운 놀이와 다리 근육 강화 운동\n🎯 높이 조절 가능으로 난이도 조절\n💸 지금 구매 시 클릭커 장난감 증정\n▶ 피트니스 보기', '', 600000.00, 3000),
(17421, 1, '🧴 펫 전용 발바닥 클린 워터', '', '✨ 물 세정 없이 닦아내는 산책 후 필수템\n💎 보습 성분 함유로 패드 보호\n📌 정기 구독 신청 시 추가 할인\n▶ 세정제 구매', '', 1890000.00, 9450),
(17422, 1, '🥣 펫 전용 경사 조절 식기 1구', '', '📌 소화가 편한 인체공학적 15도 경사\n✨ 세라믹 볼로 위생까지 잡았습니다\n💸 오픈 기념 20% 한정 세일\n▶ 식기 보러가기', '', 1280000.00, 6400),
(17423, 1, '🎒 펫 이동장 트롤리 캐리어형', '', '🎯 병원 갈 때 어깨 아픔 고민 끝!\n✨ 부드러운 주행감과 넓은 내부 공간\n🚀 오늘 사면 내일 바로 출발 가능\n▶ 이동장 쇼핑', '', 670000.00, 3350),
(17424, 1, '🥬 펫 전용 동결건조 야채 믹스', '', '💎 사료에 섞어주면 영양 밸런스 완성\n✨ 편식하는 아이들을 위한 비책\n📌 지퍼백 포장으로 신선함 유지\n▶ 야채믹스 사러가기', '', 1960000.00, 9800),
(17425, 1, '🧬 펫 성격 진단 모바일 테스트', '', '🎯 우리 아이의 성향을 전문가가 분석합니다\n✨ 맞춤형 양육 가이드 리포트 제공\n📞 1:1 채팅 상담권 포함 패키지\n▶ 테스트 신청하기', '', 1350000.00, 6750),
(17426, 1, '🪑 거실용 펫 하우스 빈백 소파', '', '✨ 인테리어를 해치지 않는 모던 디자인\n📌 아이들이 더 좋아하는 푹신한 착용감\n💰 한정 수량 40% 깜짝 할인\n▶ 빈백 보기', '', 740000.00, 3700),
(17427, 1, '🚑 24시간 응급 화상 수의사 상담', '', '🎯 한밤중 갑작스러운 증상, 당황하지 마세요\n✨ 실시간 영상으로 만나는 수의사\n📌 첫 가입 시 무료 상담권 증정\n▶ 서비스 신청하기', '', 130000.00, 650),
(17428, 1, '🐟 고양이 전용 참치 스테이크 캔', '', '💎 큼직한 살덩어리가 그대로!\n✨ 최상급 참치만을 사용한 프리미엄 캔\n💸 박스 구매 시 사은품 증정\n▶ 캔 간식 구매', '', 1420000.00, 7100),
(17429, 1, '🧣 펫 전용 리본 케이프 액세서리', '', '✨ 간단하게 묶어주면 코디 완성!\n📌 부드러운 레이스 소재로 피부 보호\n💰 3개 세트 구매 시 배송비 무료\n▶ 액세서리 보기', '', 810000.00, 4050),
(17430, 1, '🧼 펫 전용 항균 탈취 스프레이', '', '🎯 99.9% 살균력으로 냄새 근원 제거\n✨ 자연 유래 성분으로 핥아도 안심\n📌 대용량 기획 세트 특가 판매\n▶ 탈취제 사러가기', '', 200000.00, 1000),
(17431, 1, '⛺ 캠핑용 펫 전용 간이 침대', '', '💎 야외에서도 아이들의 관절을 보호하세요\n✨ 지면 냉기 차단 및 습기 방지\n💸 캠핑 시즌 한정 20% 세일\n▶ 침대 확인하기', '', 1490000.00, 7450),
(17432, 1, '🍼 펫 전용 산양유 멸균 팩 200ml', '', '🎯 소화가 쉽고 영양이 풍부한 보양식\n✨ 전 연령 급여 가능한 프리미엄 우유\n📌 10팩 구매 시 2팩 추가 증정\n▶ 우유 주문하기', '', 880000.00, 4400),
(17433, 1, '🎈 펫 생일 파티 풀 패키지 구성', '', '✨ 고깔, 안경, 가랜드, 풍선 한 번에!\n💎 완벽한 파티를 위한 모든 준비 완료\n📌 지금 구매 시 파티용 턱받이 증정\n▶ 파티팩 보기', '', 270000.00, 1350),
(17434, 1, '🧊 펫 전용 쿨링 타월 물 적심형', '', '🔥 산책 시 체온 상승을 빠르게 막아줘요\n🎯 반영구적으로 사용 가능한 특수 원단\n💰 최저가 도전 4,900원 한정\n▶ 쿨타월 확인', '', 1560000.00, 7800),
(17435, 1, '🧥 펫 전용 파자마 홈웨어 세트', '', '✨ 실내에서도 귀엽고 따뜻하게\n📌 털 빠짐 방지 효과로 집사도 편안\n🚀 오늘 사면 내일 바로 입힘\n▶ 파자마 구매하기', '', 950000.00, 4750),
(17436, 1, '🏥 슬개골 탈구 예방 거실 매트', '', '🎯 미끄러짐 방지로 아이들의 다리 보호\n✨ 인테리어와 어울리는 다양한 디자인\n📞 무료 상담 및 견적 안내 서비스\n▶ 매트 보러가기', '', 340000.00, 1700),
(17437, 1, '🧹 펫 털 제거 청소기용 특수 헤드', '', '💎 기존 청소기에 연결하여 사용하세요\n✨ 깊숙이 박힌 털까지 완벽 흡입\n💸 기간 한정 10,000원 즉시 할인\n▶ 헤드 구매하기', '', 1630000.00, 8150),
(17438, 1, '🥩 펫 수제 함박 스테이크 특식', '', '🎯 고단백 영양 보충과 특별한 맛\n✨ 원물 함량 90% 이상의 정직한 간식\n📌 당일 제조, 당일 배송 원칙\n▶ 특식 주문하기', '', 1020000.00, 5100),
(17439, 1, '🪞 펫 뷰티 온라인 아카데미', '', '✨ 집에서 배우는 셀프 미용의 모든 것\n💎 전문가의 노하우가 담긴 강의 커리큘럼\n📌 수강 완료 시 수료증 발급\n▶ 클래스 신청', '', 410000.00, 2050),
(17440, 1, '🧸 펫 전용 노즈워크 킁킁 볼', '', '🎯 지능 발달과 스트레스 해소를 동시에\n✨ 튼튼한 천 소재로 오래 놀 수 있어요\n💰 지금 구매 시 훈련용 사료 증정\n▶ 장난감 확인', '', 1700000.00, 8500),
(17441, 1, '📦 유기동물 후원 디자인 에코백', '', '✨ 가방 하나로 따뜻한 마음을 나누세요\n💎 판매 수익금 전액 보호소 기부\n📌 리미티드 일러스트 에디션\n▶ 후원 쇼핑하기', '', 1090000.00, 5450),
(17442, 1, '🛁 펫 전용 실리콘 목욕 브러쉬', '', '🎯 마사지와 세정을 한 번에 해결\n✨ 샴푸를 넣어서 사용하는 간편 방식\n🚀 주문 당일 발송 서비스 지원\n▶ 브러쉬 보기', '', 480000.00, 2400),
