(17487, 1, '🧹 펫 털 제거 청소기용 전용 노즐', '', '💎 카펫에 박힌 털을 완벽하게 흡입\n✨ 반려동물 가정 필수 가전 아이템\n💸 기간 한정 15,000원 즉시 할인\n▶ 노즐 구매하기', '', 1530000.00, 7650),
(17488, 1, '🥩 펫 수제 피자 영양 특별식', '', '🎯 홈파티 주인공은 바로 우리 아이\n✨ 고기 토핑 가득한 건강한 피자\n📌 신선 배송으로 안심하고 급여하세요\n▶ 피자 주문하기', '', 920000.00, 4600),
(17489, 1, '🪞 펫 아로마 테라피 온라인 과정', '', '✨ 아이들의 스트레스를 향기로 케어\n💎 천연 오일 배합 및 마사지 교육\n📌 수강 시 아로마 스타터 키트 증정\n▶ 클래스 신청', '', 310000.00, 1550),
(17490, 1, '🧸 노즈워크 숨바꼭질 인형 세트', '', '🎯 인형 속에 간식을 숨겨 찾아보세요\n✨ 지능 발달과 재미를 동시에 잡는 장난감\n💰 지금 구매 시 사은품 장난감 증정\n▶ 장난감 확인', '', 1600000.00, 8000),
(17491, 1, '📦 유기동물 후원 인식표 & 팔찌', '', '✨ 당신의 구매가 사료 기부로 이어집니다\n💎 판매 수익금의 50%를 정기 기부\n📌 리미티드 후원 에디션 출시\n▶ 후원 동참하기', '', 990000.00, 4950),
(17492, 1, '🛁 펫 전용 탄산 입욕제 10정', '', '🎯 목욕 시간을 즐거운 스파 시간으로\n✨ 각질 제거 및 모질 개선 효과 탁월\n🚀 오늘 주문 시 내일 도착 보장\n▶ 입욕제 보기', '', 380000.00, 1900),
(17493, 1, '👃 펫 전용 탈취제 대용량 기획팩', '', '💎 오줌 냄새와 체취를 강력하게 제거\n✨ 유해 화학 성분 없는 안전한 선택\n📌 500ml 본품 + 1L 리필 구성\n▶ 탈취제 확인하기', '', 1670000.00, 8350),
(17494, 1, '👔 펫 전용 체크무늬 원피스 신상', '', '✨ 사랑스러운 공주님 변신 완료\n📌 부드러운 코튼 소재로 편안함 보장\n💰 시즌 오프 30% 즉시 할인 중\n▶ 원피스 보러가기', '', 1060000.00, 5300),
(17495, 1, '🚿 스마트 자동 정수기 필터 팩', '', '🎯 매일매일 깨끗한 물을 마시는 습관\n✨ 미세 불순물을 걸러주는 강력 필터\n💸 정기 구독 시 추가 할인 혜택\n▶ 필터 구매하기', '', 450000.00, 2250),
(17496, 1, '🚪 방문 설치형 펫 안전 펜스', '', '✨ 아이들 출입 금지 구역 설정의 정석\n📌 튼튼한 프레임과 이중 잠금 시스템\n📞 수도권 무료 방문 설치 서비스\n▶ 펜스 보기', '', 1740000.00, 8700),
(17497, 1, '🧶 고양이 캣닢 인형 생선 세트', '', '💎 냥이들이 안고 발차기하는 장난감\n✨ 고함량 국산 캣닢으로 기분 업!\n📌 1+1 혜택으로 가성비 만점\n▶ 인형 사러가기', '', 1130000.00, 5650),
(17498, 1, '🏥 펫 응급처치 키트 가정용', '', '🎯 비상시 당황하지 말고 챙기세요\n✨ 붕대, 소독약 등 12종 필수 구성\n📌 보관용 전용 파우치 포함\n▶ 구급함 확인', '', 520000.00, 2600),
(17499, 1, '🥫 고양이 주식 파우치 대용량팩', '', '🔥 영양 균형 완벽한 맛있는 습식\n📌 수분 함량이 높아 신장 건강에 도움\n💰 박스 구매 시 최저가 혜택 제공\n▶ 파우치 쟁여두기', '', 1810000.00, 9050),
(17500, 1, '🎀 펫 전용 레이스 케이프 왕관', '', '✨ 견생샷/묘생샷 촬영 필수 아이템\n💎 가벼운 무게로 착용 거부감 제로\n📌 생일 파티 패키지 베스트 상품\n▶ 케이프 보러가기', '', 1200000.00, 6000);
